import { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, Command, User, Calendar, FileText, Settings, LayoutGrid, X } from 'lucide-react';
import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

function cn(...inputs: ClassValue[]) {
    return twMerge(clsx(inputs));
}

interface CommandPaletteProps {
    isOpen: boolean;
    onClose: () => void;
    onSelect: (tab: string) => void;
    theme?: 'light' | 'dark';
}

const NAV_ITEMS = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutGrid, category: 'Navigation' },
    { id: 'appointments', label: 'Appointments', icon: Calendar, category: 'Navigation' },
    { id: 'patients', label: 'Patient Database', icon: User, category: 'Clinical' },
    { id: 'emr', label: 'Electronic Medical Records', icon: FileText, category: 'Clinical' },
    { id: 'settings', label: 'System Settings', icon: Settings, category: 'Admin' },
];

export function CommandPalette({ isOpen, onClose, onSelect, theme }: CommandPaletteProps) {
    const [query, setQuery] = useState('');
    const [selectedIndex, setSelectedIndex] = useState(0);
    const inputRef = useRef<HTMLInputElement>(null);
    const isDark = theme === 'dark';

    useEffect(() => {
        if (isOpen) {
            setQuery('');
            setSelectedIndex(0);
            setTimeout(() => inputRef.current?.focus(), 50);
        }
    }, [isOpen]);

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (!isOpen) return;

            if (e.key === 'ArrowDown') {
                e.preventDefault();
                setSelectedIndex(prev => (prev + 1) % filteredItems.length);
            } else if (e.key === 'ArrowUp') {
                e.preventDefault();
                setSelectedIndex(prev => (prev - 1 + filteredItems.length) % filteredItems.length);
            } else if (e.key === 'Enter') {
                e.preventDefault();
                if (filteredItems[selectedIndex]) {
                    onSelect(filteredItems[selectedIndex].id);
                    onClose();
                }
            } else if (e.key === 'Escape') {
                onClose();
            }
        };

        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [isOpen, selectedIndex, query]);

    const filteredItems = NAV_ITEMS.filter(item =>
        item.label.toLowerCase().includes(query.toLowerCase()) ||
        item.category.toLowerCase().includes(query.toLowerCase())
    );

    return (
        <AnimatePresence>
            {isOpen && (
                <div className="fixed inset-0 z-[100] flex items-start justify-center pt-[15vh] px-4">
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="absolute inset-0 bg-slate-950/20 backdrop-blur-sm"
                    />

                    <motion.div
                        initial={{ opacity: 0, scale: 0.95, y: -20 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.95, y: -20 }}
                        className={cn(
                            "w-full max-w-2xl glass-premium rounded-[2.5rem] overflow-hidden shadow-2xl relative z-10",
                            isDark ? "bg-slate-900/80 border-white/10" : "bg-white/70 border-white/50"
                        )}
                    >
                        <div className="p-6 border-b border-white/10 flex items-center gap-4">
                            <Search className="text-primary animate-pulse" size={24} />
                            <input
                                ref={inputRef}
                                value={query}
                                onChange={(e) => setQuery(e.target.value)}
                                placeholder="Search clinical nodes, patients, or settings..."
                                className="w-full bg-transparent outline-none text-xl font-medium placeholder:text-slate-400"
                            />
                            <div className="flex items-center gap-1.5 px-3 py-1.5 rounded-xl bg-slate-500/10 border border-slate-500/10 text-[10px] font-bold text-slate-500">
                                <Command size={12} />
                                <span>K</span>
                            </div>
                            <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                                <X size={20} className="text-slate-400" />
                            </button>
                        </div>

                        <div className="max-h-[60vh] overflow-y-auto p-4 custom-scrollbar">
                            {filteredItems.length > 0 ? (
                                <div className="space-y-6">
                                    {['Navigation', 'Clinical', 'Admin'].map(category => {
                                        const categoryItems = filteredItems.filter(i => i.category === category);
                                        if (categoryItems.length === 0) return null;

                                        return (
                                            <div key={category} className="space-y-2">
                                                <h3 className="px-4 text-[10px] font-bold uppercase tracking-widest text-primary/60">{category}</h3>
                                                {categoryItems.map((item, idx) => {
                                                    const globalIdx = filteredItems.indexOf(item);
                                                    const isActive = globalIdx === selectedIndex;

                                                    return (
                                                        <button
                                                            key={item.id}
                                                            onMouseEnter={() => setSelectedIndex(globalIdx)}
                                                            onClick={() => { onSelect(item.id); onClose(); }}
                                                            className={cn(
                                                                "w-full flex items-center justify-between p-4 rounded-2xl transition-all duration-300 group",
                                                                isActive ? "bg-primary text-white shadow-lg shadow-primary/20 scale-[1.02]" : "hover:bg-white/10 text-slate-400"
                                                            )}
                                                        >
                                                            <div className="flex items-center gap-4">
                                                                <div className={cn(
                                                                    "w-10 h-10 rounded-xl flex items-center justify-center transition-colors",
                                                                    isActive ? "bg-white/20" : "bg-slate-500/10 text-slate-400 group-hover:text-primary"
                                                                )}>
                                                                    <item.icon size={20} />
                                                                </div>
                                                                <div className="text-left">
                                                                    <p className={cn("font-bold", isActive ? "text-white" : "text-slate-700")}>{item.label}</p>
                                                                    <p className={cn("text-[10px] font-medium opacity-60", isActive ? "text-white" : "text-slate-500")}>Jump to {item.label.toLowerCase()}</p>
                                                                </div>
                                                            </div>
                                                            {isActive && (
                                                                <div className="flex items-center gap-1.5 px-2.5 py-1 rounded-lg bg-white/20 text-[9px] font-bold">
                                                                    <span>Select</span>
                                                                    <Command size={10} />
                                                                </div>
                                                            )}
                                                        </button>
                                                    );
                                                })}
                                            </div>
                                        );
                                    })}
                                </div>
                            ) : (
                                <div className="py-20 text-center space-y-4">
                                    <div className="w-16 h-16 rounded-full bg-slate-500/10 flex items-center justify-center mx-auto">
                                        <Search size={32} className="text-slate-400" />
                                    </div>
                                    <div>
                                        <p className="font-bold text-slate-400">No clinical nodes found</p>
                                        <p className="text-xs text-slate-500 mt-1">Try searching for 'Patients' or 'Dashboard'</p>
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="p-4 bg-slate-500/5 border-t border-white/5 flex justify-between items-center text-[10px] font-bold text-slate-400">
                            <div className="flex items-center gap-6">
                                <span className="flex items-center gap-1.5"><Command size={12} className="rotate-90" /> Navigate</span>
                                <span className="flex items-center gap-1.5"><Command size={12} /> Select</span>
                                <span className="flex items-center gap-1.5">ESC Close</span>
                            </div>
                            <div className="flex items-center gap-2">
                                <span className="w-1.5 h-1.5 rounded-full bg-primary animate-pulse" />
                                Smart Search Active
                            </div>
                        </div>
                    </motion.div>
                </div>
            )}
        </AnimatePresence>
    );
}

import { useState, useEffect } from 'react';
import { User, ChevronDown } from 'lucide-react';
import { supabase } from '../supabase';

interface DoctorSelectProps {
    value?: string;
    onSelect: (doctor: { id: string; name: string }) => void;
    theme?: 'light' | 'dark';
}

export function DoctorSelect({ value, onSelect, theme }: DoctorSelectProps) {
    const [doctors, setDoctors] = useState<any[]>([]);
    const [isOpen, setIsOpen] = useState(false);
    const [selected, setSelected] = useState<{ id: string; name: string } | null>(null);
    const isDark = theme === 'dark';

    useEffect(() => {
        fetchDoctors();
    }, []);

    const fetchDoctors = async () => {
        const { data } = await supabase
            .from('staff')
            .select('id, name')
            .eq('role', 'Doctor');
        if (data) setDoctors(data);

        // If initial value present, find it
        if (value) {
            const found = data?.find(d => d.id === value || d.name === value);
            if (found) setSelected(found);
        }
    };

    return (
        <div className="relative">
            <label className={`text-[8px] font-black uppercase tracking-widest mb-1.5 block ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>Attending Physician</label>
            <button
                onClick={() => setIsOpen(!isOpen)}
                className={`w-full flex items-center justify-between px-4 py-3 rounded-xl border text-sm font-bold transition-all ${isDark ? 'bg-slate-950 border-white/10 text-white' : 'bg-slate-50 border-slate-200 text-slate-700'} focus:border-primary`}
            >
                <div className="flex items-center gap-2">
                    <User size={14} className="text-primary" />
                    {selected ? selected.name : 'Select Doctor'}
                </div>
                <ChevronDown size={14} className={`transition-transform ${isOpen ? 'rotate-180' : ''}`} />
            </button>

            {isOpen && (
                <div className={`absolute top-full left-0 right-0 mt-2 z-50 rounded-2xl border shadow-2xl overflow-hidden animate-slide-up ${isDark ? 'bg-slate-900 border-white/10' : 'bg-white border-slate-100'}`}>
                    {doctors.map(doc => (
                        <div
                            key={doc.id}
                            onClick={() => {
                                setSelected(doc);
                                onSelect(doc);
                                setIsOpen(false);
                            }}
                            className={`px-5 py-4 cursor-pointer text-sm font-bold flex items-center gap-3 transition-colors ${isDark ? 'hover:bg-white/5' : 'hover:bg-slate-50'}`}
                        >
                            <div className="w-8 h-8 rounded-lg bg-primary/10 text-primary flex items-center justify-center">
                                {doc.name.charAt(0)}
                            </div>
                            {doc.name}
                        </div>
                    ))}
                    {doctors.length === 0 && (
                        <div className="p-4 text-xs text-slate-500 italic text-center">No doctors found</div>
                    )}
                </div>
            )}
        </div>
    );
}

import { Component, type ReactNode } from 'react';

interface Props {
    children: ReactNode;
}

interface State {
    hasError: boolean;
    error: Error | null;
}

export class ErrorBoundary extends Component<Props, State> {
    constructor(props: Props) {
        super(props);
        this.state = { hasError: false, error: null };
    }

    static getDerivedStateFromError(error: Error): State {
        return { hasError: true, error };
    }

    componentDidCatch(error: Error, info: any) {
        console.error('[Dentora Error Boundary]', error, info);
    }

    render() {
        if (this.state.hasError) {
            return (
                <div className="min-h-screen flex items-center justify-center p-8 bg-slate-50">
                    <div className="max-w-md w-full text-center space-y-6 p-10 bg-white rounded-[2.5rem] border border-slate-100 shadow-xl">
                        <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-[1.5rem] flex items-center justify-center mx-auto">
                            <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                                <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3.75m-9.303 3.376c-.866 1.5.217 3.374 1.948 3.374h14.71c1.73 0 2.813-1.874 1.948-3.374L13.949 3.378c-.866-1.5-3.032-1.5-3.898 0L2.697 16.126zM12 15.75h.007v.008H12v-.008z" />
                            </svg>
                        </div>
                        <div>
                            <h2 className="text-2xl font-black text-slate-800 mb-2">Something went wrong</h2>
                            <p className="text-slate-500 text-sm font-medium">
                                An unexpected error occurred. Please refresh the page to continue.
                            </p>
                            {this.state.error && (
                                <p className="mt-3 text-xs text-rose-400 font-mono bg-rose-50 px-4 py-2 rounded-xl border border-rose-100">
                                    {this.state.error.message}
                                </p>
                            )}
                        </div>
                        <button
                            onClick={() => window.location.reload()}
                            className="w-full py-4 bg-primary text-white rounded-2xl font-bold hover:bg-primary/90 transition-all shadow-lg shadow-primary/20"
                        >
                            Refresh Application
                        </button>
                    </div>
                </div>
            );
        }
        return this.props.children;
    }
}

import { Bell, Search, UserPlus, Menu, Sun, Moon, LogOut } from 'lucide-react';
import { useToast } from './Toast';
import { useState, useRef, useEffect } from 'react';
import { supabase } from '../supabase';


type UserRole = 'master' | 'admin' | 'staff' | 'patient';

interface HeaderProps {
    toggleMenu: () => void;
    userRole: UserRole;
    setUserRole: (role: UserRole) => void;
    setActiveTab: (tab: string) => void;
    setGlobalPatient: (p: any) => void;
    theme: 'light' | 'dark';
    setTheme: (theme: 'light' | 'dark') => void;
    onLogout?: () => void;
}

export function Header({ toggleMenu, userRole, setUserRole, setActiveTab, setGlobalPatient, theme, setTheme, onLogout }: HeaderProps) {
    const { showToast } = useToast();


    const [searchQuery, setSearchQuery] = useState('');
    const [liveResults, setLiveResults] = useState<any[]>([]);
    const [waitingCount, setWaitingCount] = useState(0);
    const searchRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (searchRef.current && !searchRef.current.contains(e.target as Node)) {
                setLiveResults([]);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    useEffect(() => {
        const fetchWaitingCount = async () => {
            const today = new Date().toLocaleDateString('en-CA'); // Local YYYY-MM-DD
            const { count } = await supabase
                .from('appointments')
                .select('*', { count: 'exact', head: true })
                .eq('date', today)
                .in('status', ['Confirmed', 'Checked-In', 'Pending']);
            setWaitingCount(count || 0);
        };

        fetchWaitingCount();

        // Sub-second Real-time Sync for Waiting Count
        const channel = supabase
            .channel('public:appointments:waiting_count')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'appointments' }, () => {
                fetchWaitingCount();
            })
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, []);

    const handleSearchChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const query = e.target.value;
        setSearchQuery(query);
        if (query.length > 1) {
            const { data } = await supabase
                .from('patients')
                .select('id, name, phone, gender, age')
                .or(`name.ilike.%${query}%,id.ilike.%${query}%,phone.ilike.%${query}%`)
                .limit(6);
            setLiveResults(data || []);
        } else {
            setLiveResults([]);
        }
    };

    const handleSelectPatient = async (p: any) => {
        const { data } = await supabase.from('patients').select('*, patient_history(*)').eq('id', p.id).single();
        setGlobalPatient(data);
        setActiveTab('patient-overview');
        showToast(`Loaded: ${p.name}`, 'success');
        setSearchQuery('');
        setLiveResults([]);
    };

    const handleSearch = async (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter' && searchQuery.trim()) {
            const { data } = await supabase
                .from('patients')
                .select('*, patient_history(*)')
                .or(`name.ilike.%${searchQuery}%,id.ilike.%${searchQuery}%,phone.ilike.%${searchQuery}%`)
                .limit(1);

            if (data && data.length > 0) {
                setGlobalPatient(data[0]);
                setActiveTab('patient-overview');
                showToast(`Found: ${data[0].name}`, 'success');
            } else {
                showToast('No patient found with that ID, Name or Phone', 'error');
            }
            setSearchQuery('');
            setLiveResults([]);
        }
    };

    return (
        <div className="h-16 sticky top-0 z-40 flex items-center justify-between px-4 md:px-5 transition-all duration-300"
            style={{
                background: 'var(--card-bg)',
                backdropFilter: 'blur(15px)',
                borderBottom: '1px solid var(--border-color)',
                boxShadow: '0 1px 12px var(--glass-shadow)',
            }}>
            <div className="flex items-center gap-4 flex-1">
                <button onClick={toggleMenu} className={`lg:hidden p-2.5 rounded-xl transition-all duration-300 ease-fluid active:scale-90 hover:scale-105 ${theme === 'dark' ? 'text-primary/70 hover:text-primary hover:bg-primary/10 hover:shadow-neon' : 'text-slate-600 hover:bg-slate-100'}`}>
                    <Menu size={24} />
                </button>

                {['master', 'admin', 'staff'].includes(userRole) && (
                    <div ref={searchRef} className="relative w-full max-w-sm hidden md:block group">
                        <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 transition-colors duration-300" style={{ color: 'var(--text-muted)' }} />
                        <input
                            id="global-search-input"
                            type="text"
                            value={searchQuery}
                            onChange={handleSearchChange}
                            onKeyDown={handleSearch}
                            placeholder="Global Search..."
                            className="w-full rounded-full py-1.5 pl-10 pr-4 text-xs focus:outline-none transition-all duration-300 font-sans tracking-wide"
                            style={{
                                background: 'var(--card-bg-alt)',
                                border: '1px solid var(--border-color)',
                                color: 'var(--text-main)',
                            }}
                        />
                        {liveResults.length > 0 && (
                            <div className="absolute top-full left-0 w-full mt-3 rounded-2xl overflow-hidden z-50 animate-slide-up"
                                style={{ background: 'var(--card-bg)', border: '1px solid var(--border-color)', boxShadow: '0 12px 40px var(--glass-shadow)' }}>
                                <div className="p-3 border-b text-[13px] font-bold text-center"
                                    style={{ borderColor: 'var(--border-color)', color: 'var(--primary)', background: 'var(--primary-soft)' }}>
                                    Search Results ??? Quick Access
                                </div>
                                {liveResults.map(p => (
                                    <div
                                        key={p.id}
                                        onClick={() => handleSelectPatient(p)}
                                        className="p-3.5 cursor-pointer transition-all duration-200 flex items-center gap-3 border-b last:border-0 hover:pl-5"
                                        style={{ borderColor: 'var(--border-subtle)' }}
                                        onMouseEnter={e => (e.currentTarget.style.background = 'var(--primary-soft)')}
                                        onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}
                                    >
                                        <div className="w-10 h-10 rounded-xl flex items-center justify-center font-black text-lg transition-all"
                                            style={{ background: 'var(--primary-soft)', color: 'var(--primary)' }}>
                                            {p.name.charAt(0)}
                                        </div>
                                        <div className="flex-1">
                                            <p className="font-bold text-sm" style={{ color: 'var(--text-main)' }}>{p.name}</p>
                                            <p className="text-[11px]" style={{ color: 'var(--text-muted)' }}>{p.id} ??? {p.phone}</p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}
            </div>

            <div className="flex items-center gap-3 md:gap-4 text-slate-400">
                {/* Manual role switcher hidden in production, used only by admin for development */}
                {userRole === 'master' && (
                    <div className="hidden xl:flex items-center gap-2 p-1.5 border rounded-full transition-all duration-500"
                        style={{ background: 'var(--card-bg-alt)', border: '1px solid var(--border-color)' }}>
                        {(['master', 'admin', 'staff', 'patient'] as UserRole[]).map((r) => (
                            <button
                                key={r}
                                onClick={() => setUserRole(r)}
                                className="px-4 py-1.5 rounded-full text-xs font-bold transition-all duration-300 capitalize hover:scale-105"
                                style={{
                                    background: userRole === r ? 'var(--primary)' : 'transparent',
                                    color: userRole === r ? '#fff' : 'var(--text-muted)',
                                    boxShadow: userRole === r ? '0 4px 15px var(--primary-glow)' : 'none',
                                }}
                            >
                                {r}
                            </button>
                        ))}
                    </div>
                )}

                {['master', 'admin', 'staff'].includes(userRole) && waitingCount > 0 && (
                    <div className="hidden lg:flex items-center gap-2 px-3 py-1.5 rounded-full border"
                        style={{ background: 'var(--warning-soft)', borderColor: 'var(--warning)', color: 'var(--warning)' }}>
                        <div className="w-1.5 h-1.5 rounded-full animate-pulse" style={{ background: 'var(--warning)' }} />
                        <span className="text-xs font-bold">
                            {waitingCount} {waitingCount === 1 ? 'Waiting' : 'Waiting'}
                        </span>
                    </div>
                )}

                <button onClick={() => setActiveTab('notifications')} className="relative transition-all duration-300 p-2.5 rounded-xl hover:scale-105 active:scale-90"
                    style={{ color: 'var(--text-muted)' }}
                    onMouseEnter={e => (e.currentTarget.style.background = 'var(--primary-soft)')}
                    onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}>
                    <Bell size={20} />
                    <span className="absolute top-2 right-2 w-2 h-2 rounded-full bg-red-500 border-2" style={{ borderColor: 'var(--card-bg)' }} />
                </button>

                <button
                    onClick={() => {
                        const newTheme = theme === 'dark' ? 'light' : 'dark';
                        setTheme(newTheme);
                        showToast(`Switched to ${newTheme} mode`, 'success');
                    }}
                    className="p-2.5 rounded-xl transition-all duration-300 hover:scale-105 active:scale-90"
                    style={{ color: 'var(--text-muted)' }}
                    onMouseEnter={e => (e.currentTarget.style.background = 'var(--primary-soft)')}
                    onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}
                >
                    {theme === 'dark' ? <Moon size={20} /> : <Sun size={20} />}
                </button>

                {onLogout && (
                    <button
                        onClick={onLogout}
                        className="p-2.5 rounded-xl transition-all duration-300 hover:scale-105 active:scale-90 text-rose-500"
                        onMouseEnter={e => (e.currentTarget.style.background = 'rgba(220,38,38,0.08)')}
                        onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}
                        title="Sign Out"
                    >
                        <LogOut size={20} />
                    </button>
                )}

                {['master', 'admin', 'staff'].includes(userRole) && (
