import { useState, useEffect } from 'react';
import { ShieldCheck, AlertTriangle, AlertCircle, Info, Zap } from 'lucide-react';
import { predictNoShowRisk } from '../../services/intelligence';
import type { NoShowRisk } from '../../services/intelligence';
import { motion, AnimatePresence } from 'framer-motion';

export function PredictiveScoreBadge({ patientId, compact = false }: { patientId: string; compact?: boolean }) {
    const [risk, setRisk] = useState<NoShowRisk | null>(null);
    const [loading, setLoading] = useState(true);
    const [showDetails, setShowDetails] = useState(false);

    useEffect(() => {
        if (patientId) {
            setLoading(true);
            predictNoShowRisk(patientId).then(r => {
                setRisk(r);
                setLoading(false);
            });
        }
    }, [patientId]);

    if (loading) return (
        <div className="flex items-center gap-2 animate-pulse">
            <div className="w-16 h-4 bg-slate-500/10 rounded-full" />
        </div>
    );

    if (!risk) return null;

    const getColor = (level: string) => {
        if (level === 'Low') return 'text-emerald-500 bg-emerald-500/10 border-emerald-500/20';
        if (level === 'Medium') return 'text-amber-500 bg-amber-500/10 border-amber-500/20';
        if (level === 'High') return 'text-rose-500 bg-rose-500/10 border-rose-500/20';
        return 'text-rose-600 bg-rose-600/10 border-rose-600/20 shadow-lg shadow-rose-500/5';
    };

    const getIcon = (level: string) => {
        if (level === 'Low') return ShieldCheck;
        if (level === 'Medium') return Info;
        if (level === 'High') return AlertTriangle;
        return AlertCircle;
    };

    const StatusIcon = getIcon(risk.level);

    if (compact) {
        return (
            <div className={`px-2 py-0.5 rounded-full border flex items-center gap-1 text-[8px] font-extrabold uppercase tracking-widest ${getColor(risk.level)}`}>
                <StatusIcon size={8} /> {risk.level} Risk ({risk.score}%)
            </div>
        );
    }

    return (
        <div className="relative group">
            <button
                onClick={() => setShowDetails(!showDetails)}
                className={`px-3 py-1.5 rounded-2xl border flex items-center gap-2 text-[10px] font-extrabold uppercase tracking-widest transition-all hover:scale-105 active:scale-95 ${getColor(risk.level)}`}
            >
                <Zap size={10} className={risk.level === 'Critical' ? 'animate-pulse' : ''} />
                AI Score: {risk.score}%
            </button>

            <AnimatePresence>
                {showDetails && (
                    <motion.div
                        initial={{ opacity: 0, y: 10, scale: 0.95 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: 10, scale: 0.95 }}
                        className="absolute bottom-full left-0 mb-3 w-64 p-5 rounded-3xl bg-slate-900 border border-white/10 shadow-2xl z-[100] backdrop-blur-3xl"
                    >
                        <div className="flex items-center gap-3 mb-4">
                            <div className={`p-2 rounded-xl border ${getColor(risk.level)}`}>
                                <StatusIcon size={16} />
                            </div>
                            <div>
                                <h5 className="text-sm font-bold text-white">Risk Intelligence</h5>
                                <p className="text-[10px] text-slate-500 uppercase tracking-widest font-extrabold">{risk.level} Probability Engine</p>
                            </div>
                        </div>

                        <div className="space-y-3">
                            <p className="text-[9px] font-extrabold text-slate-400 uppercase tracking-widest border-b border-white/5 pb-2">Reasoning Protocol</p>
                            {risk.reasons.map((r, i) => (
                                <div key={i} className="flex gap-2 items-start">
                                    <div className="w-1.5 h-1.5 rounded-full bg-primary mt-1 shadow-neon" />
                                    <p className="text-[10px] font-medium text-slate-300 leading-relaxed">{r}</p>
                                </div>
                            ))}
                        </div>

                        <div className="mt-5 pt-4 border-t border-white/5">
                            <p className="text-[8px] text-slate-600 font-bold uppercase tracking-widest italic">Confidence Node: 94.2%</p>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { motion } from 'framer-motion';

interface ChatMessageProps {
    role: 'user' | 'assistant';
    content: string;
    timestamp: Date;
}

export function ChatMessage({ role, content, timestamp }: ChatMessageProps) {
    const isUser = role === 'user';

    return (
        <motion.div
            initial={{ opacity: 0, y: 10, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            className={`flex flex-col ${isUser ? 'items-end' : 'items-start'} mb-4 px-4`}
        >
            <div
                className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm shadow-sm ${isUser
                    ? 'bg-primary text-white rounded-tr-none'
                    : 'bg-white border border-slate-200 text-slate-700 rounded-tl-none'
                    }`}
            >
                <div className="prose prose-sm max-w-none">
                    <ReactMarkdown
                        remarkPlugins={[remarkGfm]}
                        components={{
                            p: ({ node, ...props }) => <p className="mb-2 last:mb-0 leading-relaxed" {...props} />,
                            ul: ({ node, ...props }) => <ul className="list-disc pl-4 mb-2" {...props} />,
                            ol: ({ node, ...props }) => <ol className="list-decimal pl-4 mb-2" {...props} />,
                            li: ({ node, ...props }) => <li className="mb-1" {...props} />,
                            strong: ({ node, ...props }) => <strong className="font-bold" {...props} />,
                            table: ({ node, ...props }) => <div className="overflow-x-auto my-2"><table className="border-collapse border border-slate-200 w-full" {...props} /></div>,
                            th: ({ node, ...props }) => <th className="border border-slate-200 p-2 bg-slate-50 font-bold text-xs" {...props} />,
                            td: ({ node, ...props }) => <td className="border border-slate-200 p-2 text-xs" {...props} />,
                        }}
                    >
                        {content}
                    </ReactMarkdown>
                </div>
            </div>
            <span className="text-[10px] text-slate-400 mt-1 font-medium">
                {timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
            </span>
        </motion.div>
    );
}

import React from 'react';
import { motion } from 'framer-motion';

interface ToothChartProps {
    type: 'Adult' | 'Pediatric';
    selectedTeeth: string[];
    onToggleTooth: (tooth: string) => void;
    isDark?: boolean;
}

const ADULT_TEETH = {
    UR: ['18', '17', '16', '15', '14', '13', '12', '11'],
    UL: ['21', '22', '23', '24', '25', '26', '27', '28'],
    LR: ['48', '47', '46', '45', '44', '43', '42', '41'],
    LL: ['31', '32', '33', '34', '35', '36', '37', '38'],
};

const PEDIATRIC_TEETH = {
    UR: ['55', '54', '53', '52', '51'],
    UL: ['61', '62', '63', '64', '65'],
    LR: ['85', '84', '83', '82', '81'],
    LL: ['71', '72', '73', '74', '75'],
};

export const ToothChart: React.FC<ToothChartProps> = ({ type, selectedTeeth, onToggleTooth, isDark }) => {
    const teethData = type === 'Adult' ? ADULT_TEETH : PEDIATRIC_TEETH;

    const renderQuadrant = (teeth: string[], label: string, isUpper: boolean) => (
        <div className="flex flex-col items-center gap-2">
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{label}</span>
            <div className="flex gap-1.5">
                {teeth.map((tooth) => {
                    const isSelected = selectedTeeth.includes(tooth);
                    return (
                        <motion.button
                            key={tooth}
                            whileHover={{ scale: 1.1 }}
                            whileTap={{ scale: 0.95 }}
                            onClick={() => onToggleTooth(tooth)}
                            className={`
                                w-10 h-12 rounded-xl border-2 flex flex-col items-center justify-center transition-all duration-300
                                ${isSelected 
                                    ? 'bg-primary border-primary shadow-lg shadow-primary/30 scale-105 z-10' 
                                    : isDark 
                                        ? 'bg-slate-800/40 border-slate-700/50 hover:border-slate-500 text-slate-300' 
                                        : 'bg-white border-slate-200 hover:border-primary/50 text-slate-500'
                                }
                            `}
                        >
                            <span className={`text-[10px] font-black ${isSelected ? 'text-white' : ''}`}>
                                {tooth}
                            </span>
                            <div className={`w-4 h-5 mt-1 rounded-t-lg rounded-b-md ${isSelected ? 'bg-white/30' : 'bg-slate-200/50 dark:bg-slate-700/50'}`} />
                        </motion.button>
                    );
                })}
            </div>
        </div>
    );

    return (
        <div className={`p-4 md:p-8 rounded-[2rem] md:rounded-[2.5rem] border ${isDark ? 'bg-slate-900/30 border-slate-800/40 shadow-2xl shadow-black/20' : 'bg-slate-50/50 border-slate-100 shadow-inner'} space-y-6 md:space-y-10 overflow-hidden`}>
            {/* Upper Jaw */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-8 md:gap-12">
                <div className="overflow-x-auto pb-2 custom-scrollbar-teeth">
                    <div className="min-w-max flex flex-col items-center">
                        {renderQuadrant(teethData.UR, 'Upper Right', true)}
                    </div>
                </div>
                <div className="overflow-x-auto pb-2 custom-scrollbar-teeth border-t sm:border-t-0 pt-6 sm:pt-0 border-slate-200/50 dark:border-slate-800/50">
                    <div className="min-w-max flex flex-col items-center">
                        {renderQuadrant(teethData.UL, 'Upper Left', true)}
                    </div>
                </div>
            </div>

            {/* Divider */}
            <div className="hidden sm:flex items-center gap-4 px-4">
                <div className="flex-1 h-px bg-slate-200 dark:bg-slate-800" />
                <div className="w-2 h-2 rounded-full bg-primary/30" />
                <div className="flex-1 h-px bg-slate-200 dark:bg-slate-800" />
            </div>

            {/* Lower Jaw */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-8 md:gap-12">
                <div className="overflow-x-auto pb-2 custom-scrollbar-teeth border-t sm:border-t-0 pt-6 sm:pt-0 border-slate-200/50 dark:border-slate-800/50">
                    <div className="min-w-max flex flex-col items-center">
                        {renderQuadrant(teethData.LR, 'Lower Right', false)}
                    </div>
                </div>
                <div className="overflow-x-auto pb-2 custom-scrollbar-teeth border-t sm:border-t-0 pt-6 sm:pt-0 border-slate-200/50 dark:border-slate-800/50">
                    <div className="min-w-max flex flex-col items-center">
                        {renderQuadrant(teethData.LL, 'Lower Left', false)}
                    </div>
                </div>
            </div>

            {/* Legend */}
            <div className="flex flex-wrap justify-center gap-4 md:gap-6 pt-6 border-t border-slate-200/50 dark:border-slate-800/50">
                <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-md bg-primary shadow-sm shadow-primary/20" />
                    <span className="text-[9px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Selected</span>
                </div>
                <div className="flex items-center gap-2">
                    <div className={`w-3 h-3 rounded-md border-2 ${isDark ? 'border-slate-700' : 'border-slate-200'}`} />
                    <span className="text-[9px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Available</span>
                </div>
                <div className="flex items-center gap-2 sm:ml-auto">
                    <span className="text-[9px] font-black text-primary uppercase tracking-widest bg-primary/10 px-3 py-1 rounded-full">
                        Total: {selectedTeeth.length}
                    </span>
                </div>
            </div>

            <style>{`
                .custom-scrollbar-teeth::-webkit-scrollbar { height: 4px; }
                .custom-scrollbar-teeth::-webkit-scrollbar-track { background: transparent; }
                .custom-scrollbar-teeth::-webkit-scrollbar-thumb { 
                    background: ${isDark ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.1)'}; 
                    border-radius: 10px; 
                }
                .custom-scrollbar-teeth::-webkit-scrollbar-thumb:hover {
                    background: ${isDark ? 'rgba(255,255,255,0.2)' : 'rgba(0,0,0,0.2)'};
                }
                .custom-scrollbar-teeth { -ms-overflow-style: none; scrollbar-width: thin; }
            `}</style>
        </div>
    );
};

