                                    </td>
                                    <td className="px-8 py-5">
                                        <p className={`font-bold text-sm ${theme === 'dark' ? 'text-white' : 'text-slate-800'}`}>{item.category}</p>
                                        <p className="text-xs text-slate-400 font-medium mt-1">{item.remark || 'Direct transaction'}</p>
