import { useState, useEffect } from 'react';
import { Shield, AlertTriangle, CheckCircle, TrendingUp, BarChart2 } from 'lucide-react';

interface RiskEngineProps {
    patient: any;
    toothChartData: Record<string, any>;
    vitals: any[];
    theme?: 'light' | 'dark';
}

interface RiskFactor {
    label: string;
    score: number;
    maxScore: number;
    severity: 'low' | 'medium' | 'high';
    detail: string;
}

export function DentalRiskScore({ patient, toothChartData, vitals, theme }: RiskEngineProps) {
    const isDark = theme === 'dark';
    const [factors, setFactors] = useState<RiskFactor[]>([]);
    const [totalScore, setTotalScore] = useState(0);
    const [riskLevel, setRiskLevel] = useState<'Low' | 'Moderate' | 'High' | 'Critical'>('Low');

    useEffect(() => {
        computeRisk();
    }, [patient, toothChartData, vitals]);

    const computeRisk = () => {
        const newFactors: RiskFactor[] = [];
        let total = 0;

        // 1. Tooth conditions
        const teethWithIssues = Object.values(toothChartData).filter((t: any) => t.condition && t.condition !== 'Healthy');
        const criticalConditions = teethWithIssues.filter((t: any) => ['Abscess', 'Fractured', 'Pulpal Involvement'].includes(t.condition));
        const toothScore = Math.min(teethWithIssues.length * 5 + criticalConditions.length * 10, 30);
        newFactors.push({
            label: 'Dental Pathology',
            score: toothScore,
            maxScore: 30,
            severity: toothScore >= 20 ? 'high' : toothScore >= 10 ? 'medium' : 'low',
            detail: `${teethWithIssues.length} tooth/teeth with conditions, ${criticalConditions.length} critical`
        });
        total += toothScore;

        // 2. Blood pressure
        const latestVitals = vitals[0];
        let bpScore = 0;
        if (latestVitals?.bp_systolic) {
            if (latestVitals.bp_systolic > 160) bpScore = 20;
            else if (latestVitals.bp_systolic > 140) bpScore = 10;
            else if (latestVitals.bp_systolic > 120) bpScore = 5;
        }
        newFactors.push({
            label: 'Cardiovascular Risk',
            score: bpScore,
            maxScore: 20,
            severity: bpScore >= 15 ? 'high' : bpScore >= 8 ? 'medium' : 'low',
            detail: latestVitals ? `BP ${latestVitals.bp_systolic}/${latestVitals.bp_diastolic} mmHg` : 'No vitals recorded'
        });
        total += bpScore;

        // 3. Known allergies
        const allergies = patient?.allergies ? patient.allergies.split(',').filter(Boolean) : [];
        const allergyScore = Math.min(allergies.length * 8, 20);
        newFactors.push({
            label: 'Allergy Burden',
            score: allergyScore,
            maxScore: 20,
            severity: allergyScore >= 16 ? 'high' : allergyScore >= 8 ? 'medium' : 'low',
            detail: allergies.length > 0 ? allergies.join(', ') : 'No allergies on record'
        });
        total += allergyScore;

        // 4. Medical conditions
        const hasMedConditions = !!(patient?.medical_conditions);
        const hasMedications = !!(patient?.current_medications);
        const medScore = (hasMedConditions ? 10 : 0) + (hasMedications ? 5 : 0);
        newFactors.push({
            label: 'Systemic Comorbidities',
            score: medScore,
            maxScore: 15,
            severity: medScore >= 12 ? 'high' : medScore >= 5 ? 'medium' : 'low',
            detail: hasMedConditions ? patient.medical_conditions : 'None on record'
        });
        total += medScore;

        // 5. SpO2
        let spo2Score = 0;
        if (latestVitals?.spo2) {
            if (latestVitals.spo2 < 90) spo2Score = 15;
            else if (latestVitals.spo2 < 95) spo2Score = 8;
        }
        newFactors.push({
            label: 'Oxygen Saturation',
            score: spo2Score,
            maxScore: 15,
            severity: spo2Score >= 12 ? 'high' : spo2Score >= 5 ? 'medium' : 'low',
            detail: latestVitals?.spo2 ? `SpO2: ${latestVitals.spo2}%` : 'Not measured'
        });
        total += spo2Score;

        setFactors(newFactors);
        setTotalScore(total);

        if (total >= 60) setRiskLevel('Critical');
        else if (total >= 35) setRiskLevel('High');
        else if (total >= 15) setRiskLevel('Moderate');
        else setRiskLevel('Low');
    };

    const maxTotal = 100;
    const pct = Math.round((totalScore / maxTotal) * 100);

    const riskStyles = {
        Low: { color: 'text-emerald-400', bg: 'bg-emerald-500', bar: 'bg-emerald-500', border: 'border-emerald-500/20', badge: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' },
        Moderate: { color: 'text-amber-400', bg: 'bg-amber-500', bar: 'bg-amber-500', border: 'border-amber-500/20', badge: 'bg-amber-500/10 text-amber-400 border-amber-500/20' },
        High: { color: 'text-rose-400', bg: 'bg-rose-500', bar: 'bg-rose-500', border: 'border-rose-500/20', badge: 'bg-rose-500/10 text-rose-400 border-rose-500/20' },
        Critical: { color: 'text-red-500', bg: 'bg-red-600', bar: 'bg-red-600', border: 'border-red-500/40', badge: 'bg-red-500/20 text-red-400 border-red-500/30' },
    };
    const style = riskStyles[riskLevel];

    return (
        <div className={`p-5 rounded-2xl border transition-all ${isDark ? `bg-slate-900 ${style.border}` : `bg-white border-slate-100 shadow-sm`}`}>
            <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                    <div className={`w-8 h-8 rounded-lg flex items-center justify-center ${style.badge}`}>
                        <Shield size={16} />
                    </div>
                    <div>
                        <h4 className="font-bold text-xs">Dental Risk Score</h4>
                        <p className={`text-[8px] font-extrabold uppercase tracking-widest ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>AI-computed safety profile</p>
                    </div>
                </div>
                <div className="text-right">
                    <p className={`text-xl font-bold ${style.color}`}>{totalScore}<span className="text-[10px] font-medium opacity-50">/100</span></p>
                    <span className={`text-[7px] font-extrabold px-1.5 py-0.5 rounded-full border uppercase tracking-widest ${style.badge}`}>
                        {riskLevel} Risk
                    </span>
                </div>
            </div>

            {/* Progress Arc */}
            <div className={`w-full h-3 rounded-full mb-6 ${isDark ? 'bg-white/5' : 'bg-slate-100'}`}>
                <div
                    className={`h-full rounded-full transition-all duration-1000 ${style.bar}`}
                    style={{ width: `${pct}%` }}
                />
            </div>

            {/* Risk Factors */}
            <div className="space-y-3">
                {factors.map((f, i) => (
                    <div key={i} className="flex items-center gap-4">
                        <div className={`w-2.5 h-2.5 rounded-full shrink-0 ${f.severity === 'high' ? 'bg-rose-400' : f.severity === 'medium' ? 'bg-amber-400' : 'bg-emerald-400'}`} />
                        <div className="flex-1 min-w-0">
                            <div className="flex justify-between items-center mb-1">
                                <p className="text-xs font-bold truncate">{f.label}</p>
                                <p className={`text-[10px] font-extrabold shrink-0 ml-2 ${f.severity === 'high' ? 'text-rose-400' : f.severity === 'medium' ? 'text-amber-400' : 'text-emerald-400'}`}>
                                    {f.score}/{f.maxScore}
                                </p>
                            </div>
                            <p className={`text-[10px] truncate ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>{f.detail}</p>
                            <div className={`w-full h-1.5 rounded-full mt-1 ${isDark ? 'bg-white/5' : 'bg-slate-100'}`}>
                                <div
                                    className={`h-full rounded-full ${f.severity === 'high' ? 'bg-rose-400' : f.severity === 'medium' ? 'bg-amber-400' : 'bg-emerald-400'}`}
                                    style={{ width: `${(f.score / f.maxScore) * 100}%` }}
                                />
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            {riskLevel === 'Critical' || riskLevel === 'High' ? (
                <div className="mt-4 p-3 bg-rose-500/10 border border-rose-500/20 rounded-xl flex items-center gap-2">
                    <AlertTriangle size={14} className="text-rose-400 shrink-0" />
                    <p className="text-[10px] font-bold text-rose-400">
                        {riskLevel === 'Critical' ? 'CRITICAL: Consult physician before invasive procedures. Medical clearance required.' : 'HIGH: Pre-procedure medical history review strongly recommended.'}
                    </p>
                </div>
            ) : riskLevel === 'Low' ? (
                <div className="mt-4 p-3 bg-emerald-500/10 border border-emerald-500/20 rounded-xl flex items-center gap-2">
                    <CheckCircle size={14} className="text-emerald-400 shrink-0" />
                    <p className="text-[10px] font-bold text-emerald-400">LOW RISK: Patient is cleared for standard dental procedures.</p>
                </div>
            ) : null}
        </div>
    );
}

import { useRef, useState, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';

// An algorithmic generator for realistically shaped teeth 
// In a true medical application, this is replaced by the 32 scanned GLTF meshes.
// For this high-end demo, we procedurally generate arch-aligned shapes that resemble realistic teeth.

const ToothGeometry = ({ type, position, rotation, scale, i, isSelected, condition, onClick, onHover, onUnhover }: any) => {
    const meshRef = useRef<THREE.Mesh>(null);
    const [hovered, setHover] = useState(false);

    // We use realistic subsurface-like shading for enamel
    const materialProps = useMemo(() => {
        let conditionColor = '#f8fcff'; // Healthy/Default
        if (condition) {
            const cond = condition.toLowerCase();
            if (['decayed', 'fractured', 'abscess', 'active problem'].includes(cond)) conditionColor = '#e74c3c'; // Red
            else if (['filled', 'treated'].includes(cond)) conditionColor = '#3498db'; // Blue
            else if (['missing'].includes(cond)) conditionColor = '#95a5a6'; // Grey
            else if (['sensitive', 'watch', 'monitor'].includes(cond)) conditionColor = '#f1c40f'; // Yellow
            else if (['implant', 'crown placed', 'bridge abutment', 'crown'].includes(cond)) conditionColor = '#2ecc71'; // Green
            else if (['rct done'].includes(cond)) conditionColor = '#e67e22'; // Orange
        }

        const baseColor = isSelected ? '#135bec' : (hovered ? '#4cf0ff' : conditionColor);

        return {
            color: baseColor,
            roughness: condition === 'missing' ? 1 : 0.2, // Missing looks duller
            metalness: 0.1,
            emissive: isSelected ? '#135bec' : '#000000',
            emissiveIntensity: isSelected ? 0.2 : 0,
            transparent: true,
            opacity: condition === 'missing' ? 0.2 : 1 // Hide missing teeth slightly
        };
    }, [isSelected, hovered, condition]);

    // Procedural subtle animation for interactive feel
    useFrame((state) => {
        if (meshRef.current && hovered && !isSelected) {
            meshRef.current.position.y += Math.sin(state.clock.elapsedTime * 5) * 0.005;
        }
    });

    const handlePointerOver = (e: any) => {
        e.stopPropagation();
        setHover(true);
        onHover(i);
        document.body.style.cursor = 'pointer';
    };

    const handlePointerOut = () => {
        setHover(false);
        onUnhover();
        document.body.style.cursor = 'auto';
    };

    const handleClick = (e: any) => {
        e.stopPropagation();
        onClick(i);
    };

    return (
        <mesh
            ref={meshRef}
            position={position}
            rotation={rotation}
            scale={scale}
            onPointerOver={handlePointerOver}
            onPointerOut={handlePointerOut}
            onClick={handleClick}
            castShadow
            receiveShadow
        >
            {/* We use specific geometries with soft scaling and radius rather than hard blocks */}
            {type === 'incisor' && <sphereGeometry args={[0.3, 32, 16]} />}
            {type === 'canine' && <sphereGeometry args={[0.35, 32, 16]} />}
            {type === 'premolar' && <sphereGeometry args={[0.4, 32, 16]} />}
            {type === 'molar' && <boxGeometry args={[0.6, 0.6, 0.6, 16, 16, 16]} />}

            <meshStandardMaterial {...materialProps} />
        </mesh>
    );
};

export function RealisticDentition({ selectedTooth, onSelectTooth, toothChartData = {} }: { selectedTooth: number | null, onSelectTooth: (num: number) => void, toothChartData?: any }) {

    // Generate the upper and lower arch (32 teeth) positioned procedurally in a U-shape
    const renderArch = (isUpper: boolean) => {
        const teeth = [];
        const radius = 3.5; // Radius of the dental arch
        const archY = isUpper ? 0.6 : -0.6; // Y separation between upper and lower

        const upperIds = [18, 17, 16, 15, 14, 13, 12, 11, 21, 22, 23, 24, 25, 26, 27, 28];
        const lowerIds = [48, 47, 46, 45, 44, 43, 42, 41, 31, 32, 33, 34, 35, 36, 37, 38];
        const idMap = isUpper ? upperIds : lowerIds;

        for (let i = 0; i < 16; i++) {
            // Calculate angle along the U-shape (semi-circle)
            const angle = Math.PI - (i * Math.PI) / 15;

            const x = Math.cos(angle) * (radius - (i === 7 || i === 8 ? 0.5 : 0)); // Slightly flatten front
            const z = Math.sin(angle) * radius * 1.5; // Elongate the arch

            // Determine tooth type based on position
            let type = 'molar';
            if (i >= 5 && i <= 10) type = 'incisor';
            if (i === 4 || i === 11) type = 'canine';
            if (i === 3 || i === 12 || i === 2 || i === 13) type = 'premolar';

            // Subtle rotation so teeth follow the curve
            const rotationY = -angle + Math.PI / 2;
            const rotationX = isUpper ? 0.1 : -0.1; // Flare out slightly
            const rotationZ = (i - 7.5) * (isUpper ? -0.05 : 0.05);

            const toothId = idMap[i];
            const toothInfo = toothChartData[toothId];
            const tCondition = toothInfo ? toothInfo.condition : null;

            teeth.push(
                <ToothGeometry
                    key={toothId}
                    i={toothId}
                    type={type}
                    position={[x, archY, z]}
                    rotation={[rotationX, rotationY, rotationZ]}
                    scale={
                        type === 'molar' ? [1.2, 1.5, 1.2] :
                            type === 'premolar' ? [1.0, 1.6, 0.9] :
                                type === 'canine' ? [0.8, 2.0, 0.8] :
                                    [1.2, 2.0, 0.4] // incisor
                    }
                    isSelected={selectedTooth === toothId}
                    condition={tCondition}
                    onClick={onSelectTooth}
                    onHover={() => { }}
                    onUnhover={() => { }}
                />
            );
        }
        return teeth;
    };

    return (
        <group position={[0, 0, -2]}>
            {renderArch(true)}
            {renderArch(false)}
        </group>
    );
}

import { useState, useEffect } from 'react';
import {
    ChevronLeft, ChevronRight, Clock, Plus,
    User, Search, RefreshCw, Calendar as CalendarIcon,
    Users, MoreHorizontal, CheckCircle2, AlertCircle
} from 'lucide-react';
import { supabase } from '../../supabase';
import { useToast } from '../Toast';
import { motion, AnimatePresence } from 'framer-motion';

const TIME_SLOTS = [
    '09:00', '09:30', '10:00', '10:30', '11:00', '11:30',
    '12:00', '12:30', '13:00', '13:30', '14:00', '14:30',
    '15:00', '15:30', '16:00', '16:30', '17:00', '17:30', '18:00'
];

export function DoctorCalendar({ theme, setActiveTab }: { theme?: 'light' | 'dark'; setActiveTab?: (t: string) => void }) {
    const { showToast } = useToast();
    const isDark = theme === 'dark';
    const today = new Date().toISOString().split('T')[0];

    const [date, setDate] = useState(today);
    const [doctors, setDoctors] = useState<any[]>([]);
    const [appointments, setAppointments] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [isQuickBooking, setIsQuickBooking] = useState<{ doc: any, time: string } | null>(null);
    const [quickFormData, setQuickFormData] = useState({ patient_id: '', type: 'Consultation', notes: '' });
    const [searchPatients, setSearchPatients] = useState<any[]>([]);
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        fetchInitialData();
        const sub = supabase.channel('doc_cal')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'appointments' }, fetchAppointments)
            .subscribe();
        return () => { supabase.removeChannel(sub); };
    }, [date]);

    async function fetchInitialData() {
        setLoading(true);
        try {
            // Fetch doctors (staff with role like 'Doctor' or 'Surgeon')
            const { data: staff } = await supabase.from('staff').select('*');
            const docs = staff?.filter((s: any) =>
                s.role?.toLowerCase().includes('doctor') ||
                s.role?.toLowerCase().includes('surgeon') ||
                s.role?.toLowerCase().includes('dentist')
            ) || [];

            // Add a default doctor if none found for demo purposes
            if (docs.length === 0) {
                docs.push({ id: 'jenkins', name: 'Dr. Jenkins', role: 'Chief Dentist' });
            }

            setDoctors(docs);
            await fetchAppointments();
        } catch (e) {
            showToast('Failed to load clinical personnel', 'error');
        } finally {
            setLoading(false);
        }
    }

    async function fetchAppointments() {
        const { data } = await supabase.from('appointments').select('*').eq('date', date);
        setAppointments(data || []);
    }

    const handleSearchPatients = async (term: string) => {
        setSearchTerm(term);
        if (term.length < 2) {
            setSearchPatients([]);
            return;
        }
        const { data } = await supabase.from('patients').select('id, name, last_name').ilike('name', `%${term}%`).limit(5);
        setSearchPatients(data || []);
    };

    const handleSaveQuickSession = async () => {
        if (!isQuickBooking) return;
        const selectedPatient = searchPatients.find(p => p.id === quickFormData.patient_id) || searchPatients[0];
        
        const newApt = {
            patient_id: quickFormData.patient_id,
            name: selectedPatient ? `${selectedPatient.name} ${selectedPatient.last_name || ''}` : 'Quick Patient',
            doctor_id: isQuickBooking.doc.id,
            doctor_name: isQuickBooking.doc.name,
            date: date,
            time: isQuickBooking.time,
            type: quickFormData.type,
            notes: quickFormData.notes || 'Routine checkup',
            status: 'Confirmed'
        };

        const { error } = await supabase.from('appointments').insert(newApt);
        if (error) {
            showToast('Failed to record session', 'error');
        } else {
            showToast(`Recording book session for ${isQuickBooking.doc.name}`, 'success');
            setIsQuickBooking(null);
            setQuickFormData({ patient_id: '', type: 'Consultation', notes: '' });
            fetchAppointments();
        }
    };

    const prevDay = () => {
        const d = new Date(date);
        d.setDate(d.getDate() - 1);
        setDate(d.toISOString().split('T')[0]);
    };

    const nextDay = () => {
        const d = new Date(date);
        d.setDate(d.getDate() + 1);
        setDate(d.toISOString().split('T')[0]);
    };

    const getApptAt = (doctorId: string, doctorName: string, time: string) => {
        return appointments.find(a =>
            a.time?.startsWith(time) &&
            (a.doctor_id === doctorId || a.doctor_name === doctorName)
        );
    };

    const handleAddSession = (doc: any, time: string) => {
        setIsQuickBooking({ doc, time });
    };

    return (
        <div className="animate-slide-up space-y-6 pb-20">
            {/* Header */}
            <div className={`p-5 md:p-6 rounded-2xl border flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4 ${isDark ? 'bg-slate-900 border-white/5' : 'bg-white border-slate-100 shadow-sm'}`}>
                <div>
                    <h2 className="text-lg font-bold tracking-tight">Doctor Schedule</h2>
                    <p className={`text-[10px] font-bold uppercase tracking-wider mt-0.5 ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>
                        Patient flow for {date === today ? 'Today' : date}
                    </p>
                </div>
                <div className="flex items-center gap-3">
                    <div className={`flex items-center p-1 rounded-xl border ${isDark ? 'bg-white/5 border-white/10' : 'bg-slate-50 border-slate-200'}`}>
                        <button onClick={prevDay} className="p-2 rounded-lg hover:bg-primary/10 hover:text-primary transition-all text-slate-400"><ChevronLeft size={18} /></button>
                        <div className="px-4 flex flex-col items-center">
