import { useState, useEffect } from 'react';
import {
    Award,
    Gift,
    TrendingUp,
    Users,
    ArrowRight,
    Star,
    Coins,
    History,
    Zap,
    MessageSquare
} from 'lucide-react';
import { supabase } from '../../supabase';
import { useToast } from '../Toast';

export function LoyaltyHub({ userRole, theme }: { userRole: string; theme?: 'light' | 'dark' }) {
    const { showToast } = useToast();
    const isDark = theme === 'dark';
    const [patients, setPatients] = useState<any[]>([]);
    const [stats, setStats] = useState({
        totalPoints: 0,
        activeMembers: 0,
        totalRewards: 0
    });
    const [search, setSearch] = useState('');

    useEffect(() => {
        fetchLoyaltyData();
    }, []);

    const fetchLoyaltyData = async () => {
        const { data } = await supabase
            .from('patients')
            .select('id, name, loyalty_points, last_visit:appointments(date)')
            .order('loyalty_points', { ascending: false });

        if (data) {
            setPatients(data);
            const total = data.reduce((acc, p) => acc + (p.loyalty_points || 0), 0);
            const active = data.filter(p => (p.loyalty_points || 0) > 0).length;
            setStats({
                totalPoints: total,
                activeMembers: active,
                totalRewards: data.filter(p => (p.loyalty_points || 0) > 1000).length
            });
        }
    };

    const addPoints = async (id: string, points: number, reason: string) => {
        const patient = patients.find(p => p.id === id);
        const currentPoints = patient?.loyalty_points || 0;

        const { error } = await supabase.from('patients')
            .update({ loyalty_points: currentPoints + points })
            .eq('id', id);

        if (!error) {
            showToast(`Awarded ${points} points for ${reason}`, 'success');
            // Log transaction in history table
            await supabase.from('loyalty_history').insert({
                patient_id: id,
                points: points,
                reason: reason
            });
            fetchLoyaltyData();
        }
    };

    const filteredPatients = patients.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));

    return (
        <div className="animate-slide-up space-y-8">
            <div className="flex justify-between items-center">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight">Patient Rewards Engine</h2>
                    <p className={`text-sm font-medium mt-1 ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>
                        Automated loyalty tiers and referral incentive tracking
                    </p>
                </div>
            </div>

            {/* Loyalty Analytics */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {[
                    { label: 'Circulating D-Points', value: stats.totalPoints.toLocaleString(), icon: Coins, color: 'text-amber-500' },
                    { label: 'Loyalty Participation', value: stats.activeMembers.toString(), icon: Zap, color: 'text-primary' },
                    { label: 'Reward Tier Eligible', value: stats.totalRewards.toString(), icon: Award, color: 'text-emerald-500' }
                ].map((s, i) => (
                    <div key={i} className="p-8 rounded-[2rem] border relative overflow-hidden" style={{ background: 'var(--card-bg)', borderColor: 'var(--border-color)', boxShadow: '0 1px 8px var(--glass-shadow)' }}>
                        <div className={`absolute top-0 right-0 p-8 opacity-5 ${s.color}`}><s.icon size={64} /></div>
                        <p className="text-xs font-semibold mb-3" style={{ color: 'var(--text-muted)' }}>{s.label}</p>
                        <h3 className="text-3xl font-bold" style={{ color: 'var(--text-dark)' }}>{s.value}</h3>
                    </div>
                ))}
            </div>

            <div className="p-8 rounded-[2.5rem] border" style={{ background: 'var(--card-bg)', borderColor: 'var(--border-color)', boxShadow: '0 1px 8px var(--glass-shadow)' }}>
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
                    <h3 className="text-xl font-bold">Reward Leaderboard</h3>
                    <div className="relative flex-1 max-w-md">
                        <MessageSquare className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                        <input
                            placeholder="Find member..."
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            className={`w-full rounded-2xl px-12 py-4 font-medium outline-none border transition-all text-sm`}
                            style={{ background: 'var(--card-bg)', borderColor: 'var(--border-color)', color: 'var(--text-main)' }}
                        />
                    </div>
                </div>

                <div className="space-y-4">
                    {filteredPatients.map((p, i) => {
                        const level = p.loyalty_points > 2000 ? 'Platinum' : p.loyalty_points > 1000 ? 'Gold' : p.loyalty_points > 500 ? 'Silver' : 'Bronze';
                        const levelColors = {
                            Platinum: 'bg-emerald-500 shadow-emerald-500/20',
                            Gold: 'bg-amber-500 shadow-amber-500/20',
                            Silver: 'bg-slate-400 shadow-slate-400/20',
                            Bronze: 'bg-rose-400 shadow-rose-400/20'
                        };

                        return (
                            <div key={p.id} className="p-6 rounded-[2rem] border group transition-all flex items-center justify-between" style={{ background: 'var(--card-bg-alt)', borderColor: 'var(--border-color)' }}>
                                <div className="flex items-center gap-6">
                                    <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-bold text-lg text-white shadow-lg ${levelColors[level as keyof typeof levelColors]}`}>
                                        {i + 1}
                                    </div>
                                    <div>
                                        <h4 className="font-bold text-lg">{p.name}</h4>
                                        <div className="flex items-center gap-3">
                                            <span className={`text-xs font-semibold ${level === 'Platinum' ? 'text-emerald-500' : 'text-slate-500'}`}>
                                                {level} Tier
                                            </span>
                                            <p className="text-[10px] font-medium text-slate-400">ID: {p.id.slice(0, 8)}</p>
                                        </div>
                                    </div>
                                </div>

                                <div className="flex items-center gap-10">
                                    <div className="text-right">
                                        <p className="text-2xl font-bold text-amber-500 flex items-center justify-end gap-2">
                                            {p.loyalty_points || 0}
                                            <Coins size={18} />
                                        </p>
                                        <p className="text-xs font-semibold text-slate-500">Available Points</p>
                                    </div>
                                    <div className="flex gap-2">
                                        <button onClick={() => addPoints(p.id, 100, 'Visit Completion')} className="p-3 rounded-xl border transition-all hover:scale-105" title="Reward Completion (+100)"
                                            style={{ background: 'var(--card-bg)', borderColor: 'var(--border-color)', color: 'var(--text-muted)' }}>
                                            <Zap size={18} />
                                        </button>
                                        <button onClick={() => addPoints(p.id, 500, 'New Referral')} className={`p-3 rounded-xl border transition-all hover:scale-105 ${isDark ? 'bg-white/5 border-white/10 text-slate-400 hover:text-emerald-500' : 'bg-white border-slate-200 text-slate-400 hover:text-emerald-500'}`} title="Referral Bonus (+500)">
                                            <Users size={18} />
                                        </button>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import {
    TrendingUp, Users, Activity,
    ArrowUpRight, BarChart3,
    Globe, PieChart, Target, Star,
    UserPlus, ShieldCheck, Mail, Lock, Building,
    CalendarDays, LayoutPanelLeft, ChevronRight, X,
    Plus, Shield, CreditCard, Clock,    CheckCircle2, Terminal
} from 'lucide-react';
import { Modal } from '../Modal';
import { supabase } from '../../supabase';
import { useToast } from '../Toast';
import {
    XAxis, YAxis, CartesianGrid,
    Tooltip, ResponsiveContainer, AreaChart, Area,
} from 'recharts';
import { motion, AnimatePresence } from 'framer-motion';
import { CustomSelect } from '../ui/CustomControls';

export function MasterPanel({ theme }: { theme?: 'light' | 'dark' }) {
    const { showToast } = useToast();
    const isDark = theme === 'dark';
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState({
        totalRevenue: 0, netProfit: 0, patientGrowth: 0,
        activeStaff: 0, avgTicket: 0, conversionRate: 0
    });
    const [revenueData, setRevenueData] = useState<any[]>([]);
    const [topDoctors, setTopDoctors] = useState<any[]>([]);
    const [activeView, setActiveView] = useState<'analytics' | 'clinics' | 'logs' | 'requests'>('analytics');
    const [admins, setAdmins] = useState<any[]>([]);
    const [logs, setLogs] = useState<any[]>([]);
    const [requests, setRequests] = useState<any[]>([]);
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [selectedAdmin, setSelectedAdmin] = useState<any>(null);
    const [isAdminDetailsOpen, setIsAdminDetailsOpen] = useState(false);

    const [newAdmin, setNewAdmin] = useState({ name: '', clinic: '', owner_name: '' });

    const fetchMasterData = async () => {
        setLoading(true);
        try {
            // Fetch Global Stats
            const { data: globalBills } = await supabase.from('bills').select('amount, date, doctor_name');
            const totalRev = globalBills?.reduce((acc, b) => acc + (Number(b.amount) || 0), 0) || 0;

            const { data: globalAccounts } = await supabase.from('accounts').select('amount').eq('type', 'expense');
            const totalExp = globalAccounts?.reduce((acc, a) => acc + (Number(a.amount) || 0), 0) || 0;

            const { count: staffCount } = await supabase.from('staff').select('*', { count: 'exact', head: true });

            // Fetch Clinic Nodes Registry
            const { data: clinicsData } = await supabase.from('clinics').select(`
                *,
                subscriptions (*),
                patients (count),
                staff (count),
                bills (amount)
            `);

            if (clinicsData) {
                const formattedAdmins = clinicsData.map(c => {
                    const sub = c.subscriptions?.[0];
                    const clinicRevenue = c.bills?.reduce((acc: number, b: any) => acc + (Number(b.amount) || 0), 0) || 0;
                    return {
                        id: c.id,
                        clinic: c.name,
                        name: c.owner_name || 'Clinic Owner',
                        package: sub?.package_type || 'Unsubscribed',
                        status: c.status,
                        validity: sub?.validity_end ? new Date(sub.validity_end).toLocaleDateString() : 'N/A',
                        patientsCount: c.patients?.[0]?.count || 0,
                        staffCount: c.staff?.[0]?.count || 0,
                        revenue: clinicRevenue,
                        branches: c.branches_count || 1
                    };
                });
                setAdmins(formattedAdmins);
            }

            // Fetch Requests
            const { data: requestsData } = await supabase
                .from('purchase_requests')
                .select(`*, clinics(name)`)
                .eq('status', 'pending');
            setRequests(requestsData || []);

            // Fetch Logs
            const { data: logsData } = await supabase.from('admin_logs').select('*').order('created_at', { ascending: false }).limit(20);
            setLogs(logsData || []);

            setStats({
                totalRevenue: totalRev,
                netProfit: totalRev - totalExp,
                patientGrowth: 15, // Mocked for now
                activeStaff: staffCount || 0,
                avgTicket: globalBills?.length ? Math.round(totalRev / globalBills.length) : 0,
                conversionRate: 72, // Mocked for now
            });

        } catch (err) {
            console.error(err);
            showToast('Logic execution error: Registry out of sync.', 'error');
        } finally {
            setLoading(false);
        }
    };

    const handleApproveRequest = async (request: any) => {
        try {
            const validityDays = request.package_type === 'Yearly' ? 365 : 28; // Requirement says 28-day monthly
            const endDate = new Date();
            endDate.setDate(endDate.getDate() + validityDays);

            // 1. Update/Insert Subscription
            const { error: subError } = await supabase
                .from('subscriptions')
                .upsert({
                    clinic_id: request.clinic_id,
                    package_type: request.package_type,
                    validity_start: new Date().toISOString(),
                    validity_end: endDate.toISOString(),
                    status: 'active'
                });

            if (subError) throw subError;

            // 2. Mark Request as Approved
            const { error: reqError } = await supabase
                .from('purchase_requests')
                .update({ status: 'approved' })
                .eq('id', request.id);

            if (reqError) throw reqError;

            // 3. Log the action
            await supabase.from('admin_logs').insert({
                clinic_id: request.clinic_id,
                action: 'SUBSCRIBE',
                details: `Approved ${request.package_type} package for ${request.clinics?.name}`,
                performed_by: (await supabase.auth.getUser()).data.user?.id
            });

            showToast(`Node ${request.clinics?.name} upgraded to ${request.package_type}.`, 'success');
            fetchMasterData();
        } catch (err: any) {
            showToast(err.message, 'error');
        }
    };

    const handleAction = async (adminId: string, action: 'activate' | 'deactivate' | 'block' | 'unlock' | 'delete') => {
        const statusMap: Record<string, string> = {
            activate: 'active',
            deactivate: 'deactivated',
            block: 'blocked',
            unlock: 'active',
            delete: 'deleted'
        };

        try {
            const { error } = await supabase
                .from('clinics')
                .update({ status: statusMap[action] })
                .eq('id', adminId);

            if (error) throw error;

            // Log the action
            await supabase.from('admin_logs').insert({
                clinic_id: adminId,
                action: action.toUpperCase(),
                details: `Admin ${action}d via Master Panel`,
                performed_by: (await supabase.auth.getUser()).data.user?.id
            });

            showToast(`Protocol ${action} executed successfully.`, 'success');
            fetchMasterData();
        } catch (err: any) {
            showToast(err.message, 'error');
        }
    };

    const handleAddAdmin = async () => {
        if (!newAdmin.name || !newAdmin.clinic) {
            showToast('Incomplete parameters for node provisioning.', 'error');
            return;
        }

        try {
            // In a real scenario, we'd create a user first, but here we just provision the clinic entry
            const { data: clinic, error: clinicError } = await supabase
                .from('clinics')
                .insert([{ 
                    name: newAdmin.clinic, 
                    owner_name: newAdmin.owner_name,
                    status: 'active' 
                }])
                .select()
                .single();

            if (clinicError) throw clinicError;

            showToast(`Node ${newAdmin.clinic} provisioned at cluster entry.`, 'success');
            setIsAddModalOpen(false);
            fetchMasterData();
        } catch (err: any) {
            showToast(err.message, 'error');
        }
    };

    useEffect(() => { fetchMasterData(); }, []);

    return (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-5 duration-700">
            {/* Master Control Header */}
            <div className={`p-5 md:p-6 rounded-2xl border shadow-xl relative overflow-hidden group transition-all duration-700 ${isDark ? 'bg-slate-900/50 border-white/5' : 'bg-white border-slate-100'}`}>
                <div className="absolute top-0 right-0 p-8 opacity-5 pointer-events-none transition-transform group-hover:scale-110 duration-1000">
                    <ShieldCheck size={100} />
                </div>
                <div className="relative z-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                    <div>
                        <div className="flex items-center gap-2 mb-2">
                            <span className="w-6 h-1 bg-primary rounded-full shadow-[0_0_8px_#135bec]" />
                            <p className="text-[10px] font-bold text-primary uppercase tracking-wider">Master Panel</p>
                        </div>
                        <h1 className="text-xl md:text-2xl font-bold tracking-tight mb-1" style={{ color: isDark ? 'white' : 'var(--text-dark)' }}>Clinic Administration</h1>
                        <p className="text-xs font-medium text-slate-400">Network overview and system performance.</p>
                    </div>
                    <div className="flex items-center gap-3">
                        <button onClick={() => setIsAddModalOpen(true)} className="bg-primary hover:scale-105 active:scale-95 text-white text-[10px] font-bold uppercase tracking-wider px-5 py-2.5 rounded-lg shadow-lg transition-all flex items-center gap-2">
                            <Plus size={16} /> Add Clinic
