                                                    key={site}
                                                    type="number"
                                                    placeholder="0"
                                                    className={`w-full py-3 rounded-xl border text-center font-bold text-sm bg-transparent outline-none focus:border-primary ${isDark ? 'border-white/10' : 'border-slate-200'}`}
