import { useState, useEffect } from 'react';
import { Bell, Send, Phone, MessageCircle, Calendar, CheckCircle2, Clock, RefreshCw, Search, Plus } from 'lucide-react';
import { supabase } from '../../supabase';
import { useToast } from '../Toast';

type UserRole = 'master' | 'admin' | 'staff' | 'patient';

const STATUS_COLOR: any = {
    Sent: 'text-emerald-600 bg-emerald-50 border-emerald-200',
    Pending: 'text-amber-500 bg-amber-50 border-amber-100',
    Failed: 'text-rose-500 bg-rose-50 border-rose-200',
};

const TYPE_COLOR: any = {
    WhatsApp: 'text-emerald-600 bg-emerald-50',
    SMS: 'text-blue-600 bg-blue-50',
    Call: 'text-violet-600 bg-violet-50',
};

export function ReminderCenter({ userRole, theme }: { userRole: UserRole; theme?: 'light' | 'dark' }) {
    const { showToast } = useToast();
    const isDark = theme === 'dark';
    const [tab, setTab] = useState<'today' | 'upcoming' | 'sent'>('today');
    const [appointments, setAppointments] = useState<any[]>([]);
    const [reminders, setReminders] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [sending, setSending] = useState<string | null>(null);

    const today = new Date().toISOString().split('T')[0];
    const tomorrow = new Date(Date.now() + 86400000).toISOString().split('T')[0];
    const dayAfter = new Date(Date.now() + 172800000).toISOString().split('T')[0];

    useEffect(() => { fetchData(); }, [tab]);

    const fetchData = async () => {
        setIsLoading(true);
        let aptQuery = supabase.from('appointments').select('*').order('date', { ascending: true });

        if (tab === 'today') aptQuery = aptQuery.eq('date', today);
        else if (tab === 'upcoming') aptQuery = aptQuery.gte('date', tomorrow).lte('date', dayAfter);

        const [{ data: apts }, { data: rems }] = await Promise.all([
            aptQuery,
            supabase.from('appointment_reminders').select('*').order('created_at', { ascending: false }).limit(50)
        ]);

        setAppointments(apts || []);
        setReminders(rems || []);
        setIsLoading(false);
    };

    const buildWhatsAppMessage = (apt: any) =>
        `Hello ${apt.name},\n\nThis is a reminder for your dental appointment:\n???? Date: ${new Date(apt.date).toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'long' })}\n??? Time: ${apt.time}\n???? Type: ${apt.type}\n\nPlease arrive 10 minutes early. For any changes, call us.\n\n??? DentiSphere Clinic`;

    const handleSendWhatsApp = async (apt: any) => {
        setSending(apt.id);
        const msg = buildWhatsAppMessage(apt);
        const phone = apt.phone?.replace(/\D/g, '') || '';
        const url = `https://wa.me/${phone ? '91' + phone : ''}?text=${encodeURIComponent(msg)}`;

        // Log the reminder
        await supabase.from('appointment_reminders').insert({
            appointment_id: apt.id,
            patient_name: apt.name,
            patient_phone: apt.phone || '',
            appointment_date: apt.date,
            appointment_time: apt.time,
            appointment_type: apt.type,
            reminder_type: 'WhatsApp',
            status: 'Sent',
            sent_at: new Date().toISOString(),
            message_body: msg,
        });

        window.open(url, '_blank');
        showToast(`WhatsApp reminder sent to ${apt.name}`, 'success');
        setSending(null);
        fetchData();
    };

    const handleSendSMS = (apt: any) => {
        const msg = `Reminder: Your dental appointment is on ${apt.date} at ${apt.time}. Type: ${apt.type}. - DentiSphere`;
        const url = `sms:${apt.phone || ''}?body=${encodeURIComponent(msg)}`;
        window.open(url);
        showToast('SMS app opened', 'success');
    };

    const handleCall = (apt: any) => {
        if (!apt.phone) { showToast('No phone number on record', 'error'); return; }
        window.open(`tel:${apt.phone}`);
    };

    const handleSendBulk = async () => {
        const pending = filtered.filter(a => a.status !== 'Cancelled');
        if (!pending.length) { showToast('No appointments to remind', 'error'); return; }
        showToast(`Opening WhatsApp for ${pending.length} patient(s)...`, 'success');
        for (const apt of pending.slice(0, 5)) {
            await handleSendWhatsApp(apt);
            await new Promise(r => setTimeout(r, 400));
        }
    };

    const filtered = appointments.filter(a =>
        a.name?.toLowerCase().includes(search.toLowerCase()) ||
        (a.phone || '').includes(search)
    );

    const sentToday = reminders.filter(r => r.sent_at?.startsWith(today));
    const pending = appointments.filter(a => a.status === 'Confirmed').length;

    const inputCls = `w-full px-4 py-3 rounded-2xl border font-medium text-sm outline-none transition-all ${isDark ? 'bg-white/5 border-white/10 text-white placeholder:text-slate-500' : 'bg-white border-slate-200 text-slate-700 shadow-sm focus:border-primary'}`;

    return (
        <div className="animate-slide-up space-y-6 pb-10">
            {/* Header */}
            <div className={`p-6 rounded-[2.5rem] border flex flex-col md:flex-row justify-between items-start md:items-center gap-4 ${isDark ? 'bg-slate-900 border-white/5' : 'bg-white border-slate-100 shadow-sm'}`}>
                <div>
                    <h2 className={`text-2xl font-bold tracking-tight flex items-center gap-3 ${isDark ? 'text-white' : 'text-slate-900'}`}>
                        <div className="w-10 h-10 rounded-2xl bg-primary/10 flex items-center justify-center">
                            <Bell size={20} className="text-primary" />
                        </div>
                        Reminder Center
                    </h2>
                    <p className="text-sm font-medium text-slate-400 mt-1 ml-[52px]">Send WhatsApp, SMS & call reminders for upcoming appointments</p>
                </div>
                <button onClick={handleSendBulk} className="flex items-center gap-2 px-6 py-3.5 bg-emerald-500 text-white rounded-2xl font-bold shadow-lg shadow-emerald-500/20 hover:bg-emerald-600 active:scale-95 transition-all">
                    <Send size={16} /> Bulk Remind (WhatsApp)
                </button>
            </div>

            {/* Stats row */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {[
                    { label: "Today's Appointments", value: appointments.filter(a => !tab || tab === 'today').length, icon: Calendar, color: 'text-primary bg-primary/10' },
                    { label: 'Confirmed', value: pending, icon: CheckCircle2, color: 'text-emerald-500 bg-emerald-50' },
                    { label: 'Reminders Sent Today', value: sentToday.length, icon: Send, color: 'text-blue-500 bg-blue-50' },
                    { label: 'Pending Reminders', value: Math.max(0, filtered.length - sentToday.length), icon: Clock, color: 'text-amber-500 bg-amber-50' },
                ].map((s, i) => (
                    <div key={i} className={`p-5 rounded-[1.8rem] border ${isDark ? 'bg-slate-900 border-white/5' : 'bg-white border-slate-100 shadow-sm'}`}>
                        <div className={`w-9 h-9 rounded-xl flex items-center justify-center mb-3 ${s.color}`}>
                            <s.icon size={18} />
                        </div>
                        <p className="text-2xl font-bold">{s.value}</p>
                        <p className="text-[10px] font-extrabold uppercase tracking-widest text-slate-400 mt-1">{s.label}</p>
                    </div>
                ))}
            </div>

            {/* Tabs + Search */}
            <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
                <div className={`flex gap-1 p-1 rounded-2xl ${isDark ? 'bg-white/5' : 'bg-slate-100'}`}>
                    {[
                        { key: 'today', label: "Today" },
                        { key: 'upcoming', label: '2-Day Ahead' },
                        { key: 'sent', label: 'Sent Log' },
                    ].map(t => (
                        <button key={t.key} onClick={() => setTab(t.key as any)}
                            className={`px-5 py-2.5 rounded-xl text-sm font-bold transition-all ${tab === t.key ? 'bg-primary text-white shadow-md shadow-primary/20' : isDark ? 'text-slate-400 hover:text-white' : 'text-slate-500 hover:text-slate-900'}`}>
                            {t.label}
                        </button>
                    ))}
                </div>
                <div className="flex gap-3 w-full sm:w-auto">
                    <div className="relative flex-1 sm:w-64">
                        <Search size={15} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input type="text" placeholder="Search patient..." value={search} onChange={e => setSearch(e.target.value)} className={`${inputCls} pl-10`} />
                    </div>
                    <button onClick={fetchData} className={`p-3 rounded-2xl border transition-all ${isDark ? 'bg-white/5 border-white/10 text-slate-300 hover:text-white' : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'}`}><RefreshCw size={16} /></button>
                </div>
            </div>

            {/* Sent Log Tab */}
            {tab === 'sent' ? (
                <div className={`rounded-[2rem] border overflow-hidden ${isDark ? 'bg-slate-900 border-white/5' : 'bg-white border-slate-100 shadow-sm'}`}>
                    <div className={`px-6 py-4 border-b flex justify-between items-center ${isDark ? 'border-white/5' : 'border-slate-100'}`}>
                        <h3 className="font-bold">Reminder History</h3>
                        <span className={`text-xs font-bold px-3 py-1 rounded-lg ${isDark ? 'bg-white/5 text-slate-400' : 'bg-slate-100 text-slate-500'}`}>{reminders.length} total</span>
                    </div>
                    <div className="divide-y divide-slate-100/10">
                        {reminders.map(r => (
                            <div key={r.id} className={`px-6 py-4 flex items-center gap-4 ${isDark ? 'hover:bg-white/5' : 'hover:bg-slate-50'}`}>
                                <div className={`w-8 h-8 rounded-xl flex items-center justify-center ${TYPE_COLOR[r.reminder_type] || 'bg-slate-100 text-slate-500'}`}>
                                    {r.reminder_type === 'WhatsApp' ? <MessageCircle size={16} /> : r.reminder_type === 'SMS' ? <MessageCircle size={16} /> : <Phone size={16} />}
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="font-bold text-sm">{r.patient_name}</p>
                                    <p className="text-[11px] text-slate-400 mt-0.5">
                                        {r.appointment_date} at {r.appointment_time} ?? {r.appointment_type}
                                    </p>
                                </div>
                                <div className="flex items-center gap-3 shrink-0">
                                    <span className={`px-2.5 py-1 rounded-xl text-[10px] font-extrabold border ${STATUS_COLOR[r.status] || ''}`}>{r.status}</span>
                                    <span className="text-[10px] text-slate-400">{r.sent_at ? new Date(r.sent_at).toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' }) : '???'}</span>
                                </div>
                            </div>
                        ))}
                        {reminders.length === 0 && !isLoading && (
                            <div className="py-16 text-center">
                                <Bell size={40} className="mx-auto mb-3 opacity-20" />
                                <p className="text-slate-400 font-medium">No reminders sent yet</p>
                            </div>
                        )}
                    </div>
                </div>
            ) : (
                /* Appointments List */
                <div className={`rounded-[2rem] border overflow-hidden ${isDark ? 'bg-slate-900 border-white/5' : 'bg-white border-slate-100 shadow-sm'}`}>
                    <div className={`px-6 py-4 border-b flex justify-between items-center ${isDark ? 'border-white/5' : 'border-slate-100'}`}>
                        <h3 className="font-bold">{tab === 'today' ? "Today's Appointments" : 'Next 2 Days'}</h3>
                        <span className={`text-xs font-bold px-3 py-1 rounded-lg ${isDark ? 'bg-white/5 text-slate-400' : 'bg-slate-100 text-slate-500'}`}>{filtered.length} appointments</span>
                    </div>

                    {isLoading ? (
                        <div className="py-16 text-center">
                            <div className="w-8 h-8 border-4 border-primary/20 border-t-primary rounded-full animate-spin mx-auto mb-3" />
                            <p className="text-slate-400">Loading appointments...</p>
                        </div>
                    ) : filtered.length === 0 ? (
                        <div className="py-16 text-center">
                            <Calendar size={40} className="mx-auto mb-3 opacity-20" />
                            <p className="font-bold text-slate-400">No appointments for this period</p>
                        </div>
                    ) : (
                        <div className="divide-y divide-slate-100/10">
                            {filtered.map(apt => {
                                const alreadySent = reminders.some(r => r.appointment_id === apt.id);
                                const statusColor: any = {
                                    Confirmed: 'text-emerald-500 bg-emerald-50 border-emerald-100',
                                    Scheduled: 'text-blue-500 bg-blue-50 border-blue-100',
                                    Cancelled: 'text-rose-400 bg-rose-50 border-rose-100',
                                    Completed: 'text-slate-400 bg-slate-50 border-slate-100',
                                };
                                return (
                                    <div key={apt.id} className={`px-6 py-4 flex flex-col sm:flex-row items-start sm:items-center gap-4 ${isDark ? 'hover:bg-white/5' : 'hover:bg-slate-50'} transition-all`}>
                                        <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-bold text-lg flex-shrink-0 ${isDark ? 'bg-white/10 text-white' : 'bg-slate-100 text-slate-600'}`}>
                                            {apt.name?.charAt(0)}
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-2 flex-wrap">
                                                <p className="font-bold text-sm">{apt.name}</p>
                                                {alreadySent && (
                                                    <span className="flex items-center gap-1 text-[9px] font-extrabold text-emerald-500 bg-emerald-50 border-emerald-100 border px-2 py-0.5 rounded-full uppercase tracking-widest">
                                                        <CheckCircle2 size={9} /> Reminded
                                                    </span>
                                                )}
                                            </div>
                                            <p className="text-[11px] text-slate-400 mt-0.5">
                                                {apt.phone || 'No phone'} ?? {apt.time} ?? {apt.type}
                                                {apt.date !== today && <span className="ml-2 text-amber-500 font-bold">{apt.date}</span>}
                                            </p>
                                        </div>
                                        <div className="flex items-center gap-2 shrink-0">
                                            <span className={`px-2.5 py-1 rounded-xl text-[10px] font-extrabold border ${statusColor[apt.status] || 'bg-slate-100 text-slate-400 border-slate-200'}`}>{apt.status}</span>
                                            <button
                                                onClick={() => handleSendWhatsApp(apt)}
                                                disabled={sending === apt.id}
                                                className="flex items-center gap-1.5 px-3 py-2 rounded-xl bg-emerald-500 text-white text-[11px] font-bold shadow-sm hover:bg-emerald-600 active:scale-95 transition-all disabled:opacity-50"
                                                title="Send WhatsApp reminder"
                                            >
                                                {sending === apt.id ? <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <MessageCircle size={13} />}
                                                WA
                                            </button>
                                            <button onClick={() => handleSendSMS(apt)} className={`p-2 rounded-xl border transition-all ${isDark ? 'bg-white/5 border-white/10 text-slate-300' : 'bg-blue-50 border-blue-100 text-blue-500 hover:bg-blue-100'}`} title="SMS"><MessageCircle size={14} /></button>
                                            <button onClick={() => handleCall(apt)} className={`p-2 rounded-xl border transition-all ${isDark ? 'bg-white/5 border-white/10 text-slate-300' : 'bg-violet-50 border-violet-100 text-violet-500 hover:bg-violet-100'}`} title="Call"><Phone size={14} /></button>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            )}

            {/* Message preview box */}
            {filtered.length > 0 && tab !== 'sent' && (
                <div className={`p-5 rounded-[2rem] border ${isDark ? 'bg-white/5 border-white/10' : 'bg-slate-50 border-slate-200'}`}>
                    <p className="text-[10px] font-extrabold uppercase tracking-widest text-slate-400 mb-2">WhatsApp Message Preview</p>
                    <pre className={`text-sm font-medium whitespace-pre-wrap leading-relaxed ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>
                        {buildWhatsAppMessage(filtered[0])}
                    </pre>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Plus, ArrowLeft, ChevronDown, FileText, Download, Calendar, Users, IndianRupee, Activity, Briefcase, Pill, Stethoscope, AlertCircle, Search, Filter } from 'lucide-react';
import { supabase } from '../../supabase';
import { useToast } from '../Toast';
import { SkeletonList } from '../SkeletonLoader';
import { EmptyState } from '../EmptyState';

type ActiveReport = string | null;
type UserRole = 'master' | 'admin' | 'staff' | 'patient';

export function Reports({ userRole, theme, setActiveTab }: { userRole: UserRole; theme?: 'light' | 'dark'; setActiveTab?: (tab: string) => void }) {
    const { showToast } = useToast();
    const isDark = theme === 'dark';
    const [expandedReport, setExpandedReport] = useState<ActiveReport>(null);
    const [viewingReportDetails, setViewingReportDetails] = useState<boolean>(false);
    const [isLoading, setIsLoading] = useState(false);
    const [reportData, setReportData] = useState<any[]>([]);
    const [reportTitle, setReportTitle] = useState<string>('');
    const [reportType, setReportType] = useState<string>('financial');
    const [showDownloadMenu, setShowDownloadMenu] = useState(false);

    // Form inputs
    const [fromDate, setFromDate] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
    const [toDate, setToDate] = useState(new Date().toISOString().split('T')[0]);

    const handleGenerate = async (title: string) => {
        setReportTitle(title);
        setViewingReportDetails(true);
        let query;

        // Specialized Reporting Logic
        if (title.includes('Expenses')) {
            setReportType('financial');
            query = supabase.from('accounts').select('*').eq('type', 'expense').gte('date', fromDate).lte('date', toDate);
        } else if (title.includes('Income') || title.includes('Payment') || title.includes('Billing')) {
            setReportType('financial');
            query = supabase.from('bills').select('*, patients!patient_id(name)').gte('date', fromDate).lte('date', toDate);
        } else if (title.includes('Cash Flow')) {
            setReportType('financial');
            query = supabase.from('accounts').select('*').gte('date', fromDate).lte('date', toDate);
        } else if (title.includes('Lab')) {
            setReportType('appointment');
            query = supabase.from('lab_orders').select('*, patients!patient_id(name)').gte('order_date', fromDate).lte('order_date', toDate);
        } else if (title.includes('Acquisition') || title.includes('Directory')) {
            setReportType('patient');
            query = supabase.from('patients').select('*').gte('created_at', fromDate).lte('created_at', toDate);
        } else if (title.includes('Appointment') || title.includes('Attendance')) {
            setReportType('appointment');
            query = supabase.from('appointments').select('*').gte('date', fromDate).lte('date', toDate);
        } else if (title.includes('Symptom') || title.includes('Treatment') || title.includes('Diagnosis')) {
            setReportType('medical');
            query = supabase.from('patient_history').select('*, patients!patient_id(name)').gte('date', fromDate).lte('date', toDate);
        } else if (title.includes('Medicine') || title.includes('Pharma')) {
            setReportType('medical');
            query = supabase.from('prescriptions').select('*, patients!patient_id(name)').gte('created_at', fromDate).lte('created_at', toDate);
        } else {
            setReportType('financial');
            query = supabase.from('bills').select('*, patients!patient_id(name)').gte('date', fromDate).lte('date', toDate);
        }

        setIsLoading(true);
        const { data, error } = await query;
        setIsLoading(false);
        if (error) {
            showToast('Error fetching report data', 'error');
            console.error(error);
        } else {
            setReportData(data || []);
        }
    };

    const handleDownload = (format: 'PDF' | 'CSV') => {
        if (reportData.length === 0) {
            showToast('No data available to export.', 'error');
            return;
        }

        showToast(`Preparing ${format} for ${reportTitle}...`, 'success');

        let headers: string[] = [];
        if (reportType === 'financial') {
            headers = ['Date', 'Reference', 'Category', 'Amount (???)', 'Status'];
        } else if (reportType === 'patient') {
            headers = ['ID', 'Name', 'Age/Gender', 'Phone', 'Created At'];
        } else if (reportType === 'appointment') {
            headers = ['Date', 'Time', 'Patient', 'Type', 'Status'];
        } else if (reportType === 'medical') {
            headers = ['Date', 'Patient', 'Detail', 'Notes', 'Cost (???)'];
        }

        if (format === 'CSV') {
            let rows: string[] = [];
            if (reportType === 'financial') {
                rows = reportData.map(r => `"${r.date || r.created_at}","${r.patients?.name || r.name || 'Ref'}","${r.type || r.category || r.id}","${r.amount || r.cost || 0}","${r.status || 'Verified'}"`);
            } else if (reportType === 'patient') {
                rows = reportData.map(r => `"${r.id}","${r.name} ${r.last_name || ''}","${r.age}/${r.gender}","${r.phone}","${r.created_at}"`);
            } else if (reportType === 'appointment') {
                rows = reportData.map(r => `"${r.date}","${r.time}","${r.patients?.name || r.name}","${r.type}","${r.status}"`);
            } else if (reportType === 'medical') {
                rows = reportData.map(r => `"${r.date}","${r.patients?.name || r.name || 'N/A'}","${r.treatment || r.medication_data?.notes || 'N/A'}","${(r.notes || '').replace(/"/g, '""')}","${r.cost || 0}"`);
            }

            const csvContent = [headers.join(','), ...rows].join('\n');
            const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
            const link = document.createElement('a');
            link.href = URL.createObjectURL(blob);
            link.setAttribute('download', `${reportTitle.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.csv`);
            link.click();
            URL.revokeObjectURL(link.href);
        } else {
            // High-fidelity PDF generation via Print
            const win = window.open('', '_blank');
            if (win) {
                win.document.write(`
                    <html>
                        <head>
                            <title>${reportTitle}</title>
                            <style>
                                body { font-family: 'Inter', sans-serif; color: #1e293b; padding: 40px; }
                                .header { border-bottom: 2px solid #135bec; padding-bottom: 20px; margin-bottom: 30px; }
                                h1 { margin: 0; color: #135bec; }
                                .meta { font-size: 12px; color: #64748b; margin-top: 5px; }
                                table { width: 100%; border-collapse: collapse; margin-top: 20px; }
                                th { background: #f8fafc; text-align: left; padding: 12px; font-size: 10px; text-transform: ; color: #64748b; border-bottom: 1px solid #e2e8f0; }
                                td { padding: 12px; font-size: 12px; border-bottom: 1px solid #f1f5f9; }
                                .total-row { background: #f8fafc; font-weight: bold; }
                                .footer { margin-top: 40px; font-size: 10px; color: #94a3b8; text-align: center; }
                            </style>
                        </head>
                        <body>
                            <div class="header">
                                <h1>Dentora Clinical Analytics</h1>
                                <p class="meta">Report: ${reportTitle} | Period: ${fromDate} to ${toDate}</p>
                            </div>
                            <table>
                                <thead>
                                    <tr>${headers.map(h => `<th>${h}</th>`).join('')}</tr>
                                </thead>
                                <tbody>
                `);

                reportData.forEach(r => {
                    let cells: any[] = [];
                    if (reportType === 'financial') {
                        cells = [r.date || r.created_at, r.patients?.name || r.name || 'N/A', r.type || r.category || r.id, `???${r.amount || r.cost || 0}`, r.status || 'Verified'];
                    } else if (reportType === 'patient') {
                        cells = [r.id, `${r.name} ${r.last_name || ''}`, `${r.age}/${r.gender}`, r.phone, r.created_at?.split('T')[0]];
                    } else if (reportType === 'appointment') {
                        cells = [r.date, r.time, r.patients?.name || r.name, r.type, r.status];
                    } else if (reportType === 'medical') {
                        cells = [r.date, r.patients?.name || r.name || 'N/A', r.treatment || r.medication_data?.notes || 'N/A', r.notes || '-', `???${r.cost || 0}`];
                    }
                    win.document.write(`<tr>${cells.map(c => `<td>${c}</td>`).join('')}</tr>`);
                });

                const total = reportData.reduce((acc, curr) => acc + (Number(curr.amount || curr.cost || 0)), 0);
                if (total > 0) {
                    win.document.write(`
                        <tr class="total-row">
                            <td colspan="${headers.length - 2}" style="text-align:right">Report Aggregate Total:</td>
                            <td colspan="2">???${total.toLocaleString('en-IN')}</td>
                        </tr>
                    `);
                }

                win.document.write(`
                                </tbody>
                            </table>
                            <div class="footer">
                                <p>This is a computer-generated clinical report from Dentora. Data verified by Authenticated Sync.</p>
                                <p>Generated on ${new Date().toLocaleString()}</p>
                            </div>
                        </body>
                    </html>
                `);
                win.document.close();
                setTimeout(() => { win.print(); }, 500);
            }
        }
    };

    const toggleReport = (reportName: string) => {
        setExpandedReport(expandedReport === reportName ? null : reportName);
    };

    const ReportItem = ({ title, icon: Icon }: { title: string, icon: any }) => {
        const isExpanded = expandedReport === title;

        return (
            <div className={`border rounded-[1.5rem] overflow-hidden transition-all duration-300 ${isExpanded ? 'bg-white shadow-xl border-primary/20 ring-4 ring-primary/5 mb-6' : 'mb-2'}`}
                style={{
                    background: isExpanded ? 'var(--card-bg)' : 'var(--card-bg-alt)',
                    borderColor: isExpanded ? 'var(--primary-glow)' : 'var(--border-color)'
                }}>
                <button
                    onClick={() => toggleReport(title)}
                    className="w-full flex justify-between items-center p-5 text-left transition-colors focus:outline-none group"
                >
                    <div className="flex items-center gap-4">
                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-colors ${isExpanded ? 'bg-primary text-white' : 'bg-slate-100 text-slate-400 group-hover:bg-primary/10 group-hover:text-primary'}`}
                            style={!isExpanded ? { background: 'var(--card-bg)', color: 'var(--text-muted)' } : {}}>
                            <Icon size={20} />
                        </div>
                        <span className={`text-sm font-bold ${isExpanded ? 'text-primary' : ''}`} style={!isExpanded ? { color: 'var(--text-main)' } : {}}>{title}</span>
                    </div>
                    <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}>
                        <ChevronDown size={18} className={isExpanded ? 'text-primary' : 'text-slate-300'} />
                    </div>
                </button>

                {isExpanded && (
                    <div className="p-6 border-t animate-slide-up" style={{ background: 'var(--card-bg-alt)', borderColor: 'var(--border-color)' }}>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 items-end">
                            <div>
                                <label className="text-xs font-bold text-slate-500 mb-2 block">Reporting Start Date</label>
                                <input
                                    type="date"
                                    value={fromDate}
                                    onChange={(e) => setFromDate(e.target.value)}
                                    className="w-full rounded-xl px-4 py-3 text-sm font-bold outline-none focus:border-primary transition-all shadow-sm border"
                                    style={{ background: 'var(--card-bg)', borderColor: 'var(--border-color)', color: 'var(--text-main)' }}
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-500 mb-2 block">Reporting End Date</label>
                                <input
                                    type="date"
                                    value={toDate}
                                    onChange={(e) => setToDate(e.target.value)}
                                    className="w-full rounded-xl px-4 py-3 text-sm font-bold outline-none focus:border-primary transition-all shadow-sm border"
                                    style={{ background: 'var(--card-bg)', borderColor: 'var(--border-color)', color: 'var(--text-main)' }}
                                />
                            </div>
                            <button
                                onClick={() => handleGenerate(title)}
                                className="px-8 py-3.5 bg-primary hover:bg-primary-hover text-white font-bold rounded-xl text-sm shadow-premium shadow-primary/20 transition-all active:scale-95 whitespace-nowrap"
                            >
                                Process Report Engine
                            </button>
                        </div>
                    </div>
                )}
            </div>
        );
    };

    // --- Report Generator View ---
    if (viewingReportDetails) {
        return (
            <div className="animate-slide-up space-y-8">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                    <div>
                        <div className="flex items-center gap-2 mb-2">
                            <span className="text-xs font-bold text-primary bg-primary/10 px-3 py-1 rounded-full">Reporting Active</span>
                            <span className="text-xs font-bold text-slate-400">{fromDate} to {toDate}</span>
                        </div>
                        <h2 className="text-4xl font-sans font-bold text-text-dark tracking-tight">{reportTitle}</h2>
                    </div>
                    <div className="flex gap-3 w-full md:w-auto">
                        <div className="relative flex-1 md:flex-none">
                            <button
                                onClick={() => setShowDownloadMenu(prev => !prev)}
                                className="w-full px-6 py-3 bg-slate-900 text-white rounded-2xl font-bold text-sm flex items-center justify-center gap-2 shadow-xl active:scale-95 transition-all"
                            >
                                <Download size={18} /> Download Data
                            </button>
                            {showDownloadMenu && (
                                <div className="absolute top-full right-0 mt-2 w-48 bg-white border border-slate-100 rounded-2xl shadow-2xl z-50 overflow-hidden">
                                    <button onClick={() => { handleDownload('PDF'); setShowDownloadMenu(false); }} className="w-full text-left px-5 py-4 text-xs font-bold hover:bg-slate-50 border-b border-slate-50 flex items-center gap-3"><FileText size={16} className="text-red-500" /> Export as PDF Document</button>
                                    <button onClick={() => { handleDownload('CSV'); setShowDownloadMenu(false); }} className="w-full text-left px-5 py-4 text-xs font-bold hover:bg-slate-50 flex items-center gap-3"><Activity size={16} className="text-green-600" /> Export as CSV Sheet</button>
                                </div>
                            )}
                        </div>
                        <button
                            onClick={() => setViewingReportDetails(false)}
                            className="bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 px-6 py-3 rounded-2xl text-sm font-bold flex items-center justify-center gap-2 transition-transform active:scale-95 shadow-sm flex-1 md:flex-none"
                        >
                            <ArrowLeft size={18} /> New Report
                        </button>
                    </div>
                </div>

                <div className="border rounded-[2.5rem] shadow-sm overflow-hidden flex flex-col p-8" style={{ background: 'var(--card-bg)', borderColor: 'var(--border-color)' }}>
                    {isLoading ? (
                        <div className="space-y-6">
                            <div className="grid grid-cols-3 gap-8">
                                <div className="h-24 bg-slate-100 rounded-3xl animate-pulse" style={{ background: 'var(--card-bg-alt)' }} />
                                <div className="h-24 bg-slate-100 rounded-3xl animate-pulse" style={{ background: 'var(--card-bg-alt)' }} />
                                <div className="h-24 bg-slate-100 rounded-3xl animate-pulse" style={{ background: 'var(--card-bg-alt)' }} />
                            </div>
                            <SkeletonList rows={6} />
                        </div>
                    ) : (
                        <>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-10">
                                <div className="p-6 rounded-3xl border" style={{ background: 'var(--card-bg-alt)', borderColor: 'var(--border-color)' }}>
                                    <p className="text-[10px] font-extrabold text-slate-400 mb-2">Record Count</p>
                                    <h4 className="text-3xl font-sans font-bold" style={{ color: 'var(--text-main)' }}>{reportData.length} entries</h4>
                                </div>
                                <div className="p-6 rounded-3xl border" style={{ background: 'var(--card-bg-alt)', borderColor: 'var(--border-color)' }}>
                                    <p className="text-[10px] font-extrabold text-slate-400 mb-2">Total Financials</p>
                                    <h4 className="text-3xl font-sans font-bold text-primary">???{reportData.reduce((acc, curr) => acc + (Number(curr.amount || curr.cost || 0)), 0).toLocaleString('en-IN')}</h4>
                                </div>
                                <div className="p-6 rounded-3xl border flex items-center justify-center border-primary/10" style={{ background: 'var(--primary-glow)' }}>
                                    <div className="text-center">
                                        <p className="text-[10px] font-extrabold text-primary mb-1">Status</p>
                                        <p className="font-bold text-primary flex items-center gap-2">
                                            <span className="w-2 h-2 bg-primary rounded-full animate-ping" />
                                            Authenticated Sync
                                        </p>
                                    </div>
                                </div>
                            </div>

                            <div className="overflow-x-auto border rounded-3xl custom-scrollbar" style={{ borderColor: 'var(--border-color)' }}>
                                <table className="w-full text-left border-collapse">
                                    <thead>
                                        <tr className="border-b text-xs text-slate-400 font-bold" style={{ background: 'var(--card-bg-alt)', borderColor: 'var(--border-color)' }}>
                                            <th className="px-8 py-5">Date</th>
                                            <th className="px-8 py-5">Details</th>
                                            <th className="px-8 py-5">Amount</th>
                                            <th className="px-8 py-5 text-center">Status</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y" style={{ borderColor: 'var(--border-color)' }}>
                                        {reportData.map((row, idx) => (
                                            <tr key={idx} className="transition-colors group hover:bg-slate-50/50" style={{ borderColor: 'var(--border-color)' }}>
                                                <td className="px-8 py-5 text-sm font-bold text-slate-600" style={{ color: 'var(--text-muted)' }}>{new Date(row.date || row.created_at).toLocaleDateString()}</td>
                                                <td className="px-8 py-5">
                                                    <p className="font-bold text-base tracking-tight" style={{ color: 'var(--text-main)' }}>{row.patients?.name || row.name || 'Anonymous Object'}</p>
                                                    <p className="text-[10px] text-slate-400 font-bold mt-1">{row.type || row.id || row.treatment || 'System Transaction'}</p>
                                                </td>
                                                <td className="px-8 py-5">
                                                    <span className="font-sans font-bold text-lg text-primary">???{(row.amount || row.cost || 0).toLocaleString('en-IN')}</span>
                                                </td>
                                                <td className="px-8 py-5 text-center">
                                                    <span className="px-4 py-1.5 rounded-full text-[10px] font-extrabold border bg-green-50 text-green-600 border-green-100">Verified</span>
                                                </td>
                                            </tr>
                                        ))}
                                        {reportData.length === 0 && (
                                            <tr><td colSpan={4} className="text-center py-32 text-slate-300 font-bold italic font-sans text-xl">No records found for this period.</td></tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        </>
                    )}
                </div>
            </div>
        );
    }

    // --- Main List View ---
    return (
        <div className="animate-slide-up space-y-10 max-w-6xl mx-auto py-4">
            <div className="text-center space-y-3">
                <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-primary/10 rounded-full border border-primary/20 text-xs font-bold text-primary">Clinic Reports</div>
                <h2 className="text-5xl font-sans font-bold text-text-dark tracking-tight">Analytical Reports</h2>
                <p className="text-slate-500 font-medium text-lg max-w-2xl mx-auto">Generate and export detailed clinical and financial reports for your clinic.</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
                {/* Financial Reports */}
                <div className="space-y-6">
                    <div className="flex items-center gap-4 px-2">
                        <div className="w-12 h-12 bg-green-500/10 text-green-600 rounded-2xl flex items-center justify-center shadow-sm border border-green-500/5">
                            <IndianRupee size={24} />
                        </div>
                        <h3 className="font-sans font-bold text-2xl text-slate-800">Financial Suite</h3>
                    </div>
                    <div className="space-y-2">
                        <ReportItem title="Payment Summary Report" icon={FileText} />
                        <ReportItem title="Cash Flow Dynamics" icon={Activity} />
                        <ReportItem title="Expenses Audit" icon={Briefcase} />
                        <ReportItem title="Outstanding Receivables" icon={AlertCircle} />
                    </div>
                </div>

                {/* Patient / Medical Reports */}
                <div className="space-y-6">
                    <div className="flex items-center gap-4 px-2">
                        <div className="w-12 h-12 bg-blue-500/10 text-blue-600 rounded-2xl flex items-center justify-center shadow-sm border border-blue-500/5">
                            <Users size={24} />
                        </div>
                        <h3 className="font-sans font-bold text-2xl text-slate-800">Clinical Data</h3>
                    </div>
                    <div className="space-y-2">
                        <ReportItem title="Patient Acquisition Log" icon={Plus} />
                        <ReportItem title="Treatment Heatmap" icon={Stethoscope} />
                        <ReportItem title="Pharmaceutical Usage" icon={Pill} />
                        <ReportItem title="Symptom & Diagnosis Analysis" icon={Stethoscope} />
                        <ReportItem title="Pediatric Growth Trends" icon={Users} />
                    </div>
                </div>

                <div className="space-y-6">
                    <div className="flex items-center gap-4 px-2">
                        <div className="w-12 h-12 rounded-2xl flex items-center justify-center shadow-sm border border-purple-500/5" style={{ background: 'var(--primary-glow)', color: 'var(--primary)' }}>
                            <Calendar size={24} />
                        </div>
                        <h3 className="font-sans font-bold text-2xl" style={{ color: 'var(--text-main)' }}>Operations</h3>
                    </div>
                    <div className="space-y-2">
                        <ReportItem title="Appointment Attendance" icon={Calendar} />
                        <ReportItem title="Doctor Performance Ratio" icon={Activity} />
                        <ReportItem title="Dental Lab Workflow" icon={Briefcase} />
                        <ReportItem title="Referral Source Audit" icon={ChevronDown} />
                    </div>
                </div>
            </div>
        </div>
    );
}

