}

export function downloadLabOrderPDF(data: LabOrderData): void {
    const doc = new jsPDF({ unit: 'mm', format: 'a4' });

    addClinicHeader(
        doc,
        'DentiSphere Clinic',
        data.doctorName || 'Attending Doctor',
        'Lab Order',
        new Date(data.date).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })
    );

    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');
    doc.text(`Order ID: #${data.orderId.slice(0, 8)}`, 14, 38);

    // Info Grid
    const info = [
        ['Patient Name', data.patientName, 'Lab / Vendor', data.vendorName],
        ['Contact', data.patientPhone || 'N/A', 'Status', data.status],
        ['Teeth Reference', data.teeth || 'N/A', '', '']
    ];

    autoTable(doc, {
        startY: 42,
        body: info,
        theme: 'plain',
        bodyStyles: { fontSize: 9, textColor: DARK_COLOR, cellPadding: 2 },
        columnStyles: { 0: { fontStyle: 'bold', cellWidth: 30 }, 2: { fontStyle: 'bold', cellWidth: 30 } }
    });

    let y = (doc as any).lastAutoTable.finalY + 10;

    doc.setFont('helvetica', 'bold');
    doc.text('Order Details / Instructions:', 14, y);
    y += 6;
    doc.setFont('helvetica', 'normal');
    const splitDetails = doc.splitTextToSize(data.details || 'No additional instructions provided.', 182);
    doc.text(splitDetails, 14, y);
    y += (splitDetails.length * 5) + 10;

    doc.setFont('helvetica', 'bold');
    doc.text('Delivery Schedule:', 14, y);
    y += 6;
    const delivery = [
        ['Trial Fitment', data.deliveryDates.trial || 'TBD'],
        ['Bisque/Second Trial', data.deliveryDates.bisque || 'TBD'],
        ['Final Delivery', data.deliveryDates.final || 'TBD']
    ];
    autoTable(doc, {
        startY: y,
        body: delivery,
        theme: 'grid',
        bodyStyles: { fontSize: 9 },
        columnStyles: { 0: { fontStyle: 'bold', cellWidth: 40 } }
    });

    addFooter(doc);
    const filename = `LabOrder_${data.patientName.replace(/\s+/g, '_')}_${new Date(data.date).toISOString().split('T')[0]}.pdf`;
    doc.save(filename);
}

export interface InvoiceData {
    invoiceNumber: string;
    date: string;
    patientName: string;
    patientPhone?: string;
    patientAddress?: string;
    clinicName: string;
    clinicLocation: string;
    doctorName: string;
    treatmentName: string;
    grossAmount: number;
    discount: number;
    gstRate: number;
    gstAmount: number;
    totalAmount: number;
    paymentMethod: string;
    paymentStatus: string;
}

export function downloadInvoicePDF(data: InvoiceData): void {
    const doc = new jsPDF({ unit: 'mm', format: 'a4' });

    addClinicHeader(
        doc,
        data.clinicName || 'DentiSphere Clinic',
        data.clinicLocation + '  |  ' + data.doctorName,
        'Tax Invoice',
        new Date(data.date).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })
    );

    // "INVOICE" watermark
    doc.setFontSize(48);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(0, 123, 255);
    doc.setGState(new (doc as any).GState({ opacity: 0.05 }));
    doc.text('INVOICE', 105, 145, { align: 'center', angle: 45 });
    doc.setGState(new (doc as any).GState({ opacity: 1 }));

    // Invoice number badge
    doc.setFontSize(11);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...BRAND_COLOR);
    doc.text(`# ${data.invoiceNumber}`, 196, 38, { align: 'right' });
    doc.setFontSize(8);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(...MUTED_COLOR);
    doc.text(new Date(data.date).toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }), 196, 44, { align: 'right' });

    // Bill-to block
    doc.setFillColor(248, 250, 252);
    doc.roundedRect(14, 34, 90, 26, 3, 3, 'F');
    doc.setFontSize(7);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...MUTED_COLOR);
    doc.text('BILL TO', 18, 41);
    doc.setFontSize(11);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...DARK_COLOR);
    doc.text(data.patientName, 18, 48);
    doc.setFontSize(9);
    doc.setFont('helvetica', 'normal');
    if (data.patientPhone) doc.text(data.patientPhone, 18, 54);
    if (data.patientAddress) doc.text(data.patientAddress, 18, 58);

    // Payment block
    doc.setFillColor(248, 250, 252);
    doc.roundedRect(110, 34, 86, 26, 3, 3, 'F');
    doc.setFontSize(7);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...MUTED_COLOR);
    doc.text('PAYMENT', 114, 41);
    doc.setFontSize(11);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...DARK_COLOR);
    doc.text(data.paymentMethod, 114, 48);
    // Status badge
    const statusColors: Record<string, [number, number, number]> = {
        paid: [5, 150, 105], unpaid: [220, 50, 50], partial: [217, 119, 6]
    };
    const statusBg: Record<string, [number, number, number]> = {
        paid: [209, 250, 229], unpaid: [254, 226, 226], partial: [254, 243, 199]
    };
    const sKey = data.paymentStatus.toLowerCase();
    doc.setFillColor(...(statusBg[sKey] || [241, 245, 249]));
    doc.roundedRect(114, 51, 30, 6, 1, 1, 'F');
    doc.setFontSize(7);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...(statusColors[sKey] || [100, 116, 139]));
    doc.text(data.paymentStatus.toUpperCase(), 129, 55.5, { align: 'center' });

    // Line items table
    autoTable(doc, {
        startY: 68,
        head: [['#', 'Description', 'Amount (???)']],
        body: [[1, data.treatmentName, `???${data.grossAmount.toLocaleString('en-IN')}`]],
        headStyles: { fillColor: BRAND_COLOR, textColor: [255, 255, 255], fontStyle: 'bold', fontSize: 9 },
        bodyStyles: { fontSize: 10, textColor: DARK_COLOR },
        columnStyles: { 0: { cellWidth: 12 }, 2: { halign: 'right' } },
        margin: { left: 14, right: 14 },
    });

    let y = (doc as any).lastAutoTable.finalY + 6;

    // Totals block
    const totals: [string, string][] = [
        ['Gross Amount', `???${data.grossAmount.toLocaleString('en-IN')}`],
    ];
    if (data.discount > 0) totals.push(['Discount', `??? ???${data.discount.toLocaleString('en-IN')}`]);
    if (data.gstAmount > 0) totals.push([`GST (${data.gstRate}%)`, `???${data.gstAmount.toLocaleString('en-IN')}`]);

    doc.setDrawColor(226, 232, 240);
    totals.forEach(([label, val]) => {
        doc.setFontSize(9);
        doc.setFont('helvetica', 'normal');
        doc.setTextColor(...MUTED_COLOR);
        doc.text(label, 140, y);
        doc.setFont('helvetica', 'bold');
        doc.setTextColor(...DARK_COLOR);
        doc.text(val, 196, y, { align: 'right' });
        doc.setLineWidth(0.2);
        doc.line(130, y + 3, 196, y + 3);
        y += 8;
    });

    // Grand total
    doc.setFillColor(...BRAND_COLOR);
    doc.roundedRect(130, y, 66, 12, 2, 2, 'F');
    doc.setFontSize(11);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(255, 255, 255);
    doc.text('Net Payable', 134, y + 8);
    doc.text(`???${data.totalAmount.toLocaleString('en-IN')}`, 192, y + 8, { align: 'right' });

    // Signature
    y += 24;
    y = Math.max(y, 220);
    doc.setDrawColor(...DARK_COLOR);
    doc.setLineWidth(0.3);
    doc.line(130, y + 18, 196, y + 18);
    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...DARK_COLOR);
    doc.text(data.doctorName, 163, y + 23, { align: 'center' });
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(...MUTED_COLOR);
    doc.text('Authorized Signature', 163, y + 28, { align: 'center' });

    addFooter(doc);
    const filename = `Invoice_${data.patientName.replace(/\s+/g, '_')}_${data.invoiceNumber}.pdf`;
    doc.save(filename);
}

export interface ConsentData {
    patientName: string;
    patientPhone?: string;
    doctorName: string;
    date: string;
    title: string;
    body: string;
    signatureUrl?: string;
    formId: string;
}

export function downloadConsentPDF(data: ConsentData): void {
    const doc = new jsPDF({ unit: 'mm', format: 'a4' });

    addClinicHeader(
        doc,
        'DentiSphere Clinic',
        'Informed Consent Form',
        'Legal Record',
        new Date(data.date).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })
    );

    doc.setFillColor(240, 247, 255);
    doc.roundedRect(14, 34, 182, 18, 3, 3, 'F');
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10);
    doc.setTextColor(...DARK_COLOR);
    doc.text('Patient Name:', 18, 43);
    doc.setFont('helvetica', 'normal');
    doc.text(data.patientName, 45, 43);
    doc.setFont('helvetica', 'bold');
    doc.text('Date:', 18, 49);
    doc.setFont('helvetica', 'normal');
    doc.text(new Date(data.date).toLocaleString(), 45, 49);
    doc.setFont('helvetica', 'bold');
    doc.text('Doctor:', 110, 43);
    doc.setFont('helvetica', 'normal');
    doc.text(data.doctorName, 130, 43);
    doc.setFont('helvetica', 'bold');
    doc.text('Ref ID:', 110, 49);
    doc.setFont('helvetica', 'normal');
    doc.text(`#${data.formId.slice(0, 8)}`, 130, 49);

    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...BRAND_COLOR);
    doc.text(data.title, 14, 64);

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(...DARK_COLOR);
    const splitBody = doc.splitTextToSize(data.body, 182);
    doc.text(splitBody, 14, 72);

    let y = 72 + (splitBody.length * 5) + 10;
    y = Math.max(y, 200);
    doc.setDrawColor(...MUTED_COLOR);
    doc.line(14, y + 20, 80, y + 20);
    doc.setFontSize(8);
    doc.text('Patient Signature', 47, y + 25, { align: 'center' });

    if (data.signatureUrl) {
        try {
            doc.addImage(data.signatureUrl, 'PNG', 20, y - 5, 40, 20);
        } catch (e) {
            console.error('Signature attachment failed', e);
        }
    }

    doc.line(130, y + 20, 196, y + 20);
    doc.text('Doctor Signature / Audit', 163, y + 25, { align: 'center' });
    doc.setFont('helvetica', 'italic');
    doc.text(data.doctorName, 163, y + 18, { align: 'center' });

    addFooter(doc);
    const filename = `Consent_${data.title.replace(/\s+/g, '_')}_${data.patientName.replace(/\s+/g, '_')}.pdf`;
    doc.save(filename);
}
